const CliProviderKind = enum {
    remote_signer,
    passkey,
    zklogin,
    multisig,
};

const CliProviderAuthorizerContext = struct {
    rpc: *client.SuiRpcClient,
    argv: []const []const u8,
    response_storage: [provider_authorizer_response_storage_size]u8 = undefined,
};

const provider_command_output_limit: usize = 1024 * 1024;
const provider_command_error_snippet_limit: usize = 200;
const provider_authorizer_response_storage_size: usize = 16 * 1024;

fn parseRequiredJsonString(
    allocator: std.mem.Allocator,
    object: std.json.ObjectMap,
    comptime names: []const []const u8,
) ![]const u8 {
    return (try parseOptionalJsonString(allocator, object, names)) orelse error.InvalidCli;
}

fn parseOptionalJsonStringArray(
    allocator: std.mem.Allocator,
    object: std.json.ObjectMap,
    comptime names: []const []const u8,
) !?[]const []const u8 {
    const value = jsonObjectFieldAny(object, names) orelse return null;
    return switch (value) {
        .null => null,
        .array => |array| blk: {
            const items = try allocator.alloc([]const u8, array.items.len);
            for (array.items, 0..) |entry, index| {
                if (entry != .string or entry.string.len == 0) return error.InvalidCli;
                items[index] = try allocator.dupe(u8, entry.string);
            }
            break :blk items;
        },
        else => error.InvalidCli,
    };
}

fn parseSessionChallengeActionValue(value: std.json.Value) !client.tx_request_builder.SessionChallengeAction {
    return switch (value) {
        .string => |text| std.meta.stringToEnum(client.tx_request_builder.SessionChallengeAction, text) orelse return error.InvalidCli,
        else => error.InvalidCli,
    };
}

fn parseProviderKind(text: []const u8) !CliProviderKind {
    if (std.mem.eql(u8, text, "remote_signer") or std.mem.eql(u8, text, "remoteSigner")) return .remote_signer;
    if (std.mem.eql(u8, text, "passkey")) return .passkey;
    if (std.mem.eql(u8, text, "zklogin") or std.mem.eql(u8, text, "zkLogin")) return .zklogin;
    if (std.mem.eql(u8, text, "multisig")) return .multisig;
    return error.InvalidCli;
}

fn parseSignPersonalMessageChallengeFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.SignPersonalMessageChallenge {
    if (value != .object) return error.InvalidCli;
    return .{
        .domain = try parseRequiredJsonString(allocator, value.object, &.{"domain"}),
        .statement = try parseRequiredJsonString(allocator, value.object, &.{"statement"}),
        .nonce = try parseRequiredJsonString(allocator, value.object, &.{"nonce"}),
        .address = try parseOptionalJsonString(allocator, value.object, &.{"address"}),
        .uri = try parseOptionalJsonString(allocator, value.object, &.{"uri"}),
        .chain = (try parseOptionalJsonString(allocator, value.object, &.{"chain"})) orelse try allocator.dupe(u8, "sui"),
        .issued_at_ms = try parseOptionalJsonU64(value.object, &.{ "issued_at_ms", "issuedAtMs" }),
        .expires_at_ms = try parseOptionalJsonU64(value.object, &.{ "expires_at_ms", "expiresAtMs" }),
        .resources = (try parseOptionalJsonStringArray(allocator, value.object, &.{"resources"})) orelse &.{},
    };
}

fn parsePasskeyChallengeFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.PasskeyChallenge {
    if (value != .object) return error.InvalidCli;
    return .{
        .rp_id = try parseRequiredJsonString(allocator, value.object, &.{ "rp_id", "rpId" }),
        .challenge_b64url = try parseRequiredJsonString(allocator, value.object, &.{ "challenge_b64url", "challengeB64url" }),
        .user_name = try parseOptionalJsonString(allocator, value.object, &.{ "user_name", "userName" }),
        .user_display_name = try parseOptionalJsonString(allocator, value.object, &.{ "user_display_name", "userDisplayName" }),
        .timeout_ms = try parseOptionalJsonU64(value.object, &.{ "timeout_ms", "timeoutMs" }),
    };
}

fn parseZkLoginNonceChallengeFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.ZkLoginNonceChallenge {
    if (value != .object) return error.InvalidCli;
    return .{
        .nonce = try parseRequiredJsonString(allocator, value.object, &.{"nonce"}),
        .provider = try parseOptionalJsonString(allocator, value.object, &.{"provider"}),
        .max_epoch = try parseOptionalJsonU64(value.object, &.{ "max_epoch", "maxEpoch" }),
    };
}

fn parseSessionChallengeFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.SessionChallenge {
    if (value != .object) return error.InvalidCli;
    if (jsonObjectFieldAny(value.object, &.{ "sign_personal_message", "signPersonalMessage" })) |challenge_value| {
        return .{ .sign_personal_message = try parseSignPersonalMessageChallengeFromJsonValue(allocator, challenge_value) };
    }
    if (jsonObjectFieldAny(value.object, &.{"passkey"})) |challenge_value| {
        return .{ .passkey = try parsePasskeyChallengeFromJsonValue(allocator, challenge_value) };
    }
    if (jsonObjectFieldAny(value.object, &.{ "zklogin_nonce", "zkloginNonce" })) |challenge_value| {
        return .{ .zklogin_nonce = try parseZkLoginNonceChallengeFromJsonValue(allocator, challenge_value) };
    }
    return error.InvalidCli;
}

fn parseRemoteAuthorizationResultFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.RemoteAuthorizationResult {
    if (value != .object) return error.InvalidCli;
    const session = if (jsonObjectFieldAny(value.object, &.{"session"})) |session_value|
        switch (session_value) {
            .null => null,
            else => try parseAccountSessionFromJsonValue(allocator, session_value),
        }
    else
        null;
    return .{
        .sender = try parseOptionalJsonString(allocator, value.object, &.{"sender"}),
        .signatures = (try parseOptionalJsonStringArray(allocator, value.object, &.{"signatures"})) orelse &.{},
        .session = session,
        .supports_execute = (try parseOptionalJsonBool(value.object, &.{ "supports_execute", "supportsExecute" })) orelse true,
    };
}

fn parseRemoteAuthorizationResultJson(
    allocator: std.mem.Allocator,
    raw: []const u8,
) !client.tx_request_builder.RemoteAuthorizationResult {
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, raw, .{});
    defer parsed.deinit();
    return try parseRemoteAuthorizationResultFromJsonValue(allocator, parsed.value);
}

fn cliProviderStaticChallengePromptCallback(
    _: *anyopaque,
    _: std.mem.Allocator,
    _: client.tx_request_builder.SessionChallengeRequest,
) anyerror!client.tx_request_builder.SessionChallengeResponse {
    return error.InvalidCli;
}

fn appendProviderCommandOutputSnippet(
    writer: anytype,
    label: []const u8,
    output: []const u8,
) !void {
    const trimmed = std.mem.trim(u8, output, " \n\r\t");
    if (trimmed.len == 0) return;

    try writer.print("; {s}: ", .{label});
    const limit = @min(trimmed.len, provider_command_error_snippet_limit);
    for (trimmed[0..limit]) |ch| {
        try writer.writeByte(switch (ch) {
            '\n', '\r', '\t' => ' ',
            else => ch,
        });
    }
    if (trimmed.len > limit) try writer.writeAll("...");
}

fn recordProviderAuthorizerFailure(
    ctx: *const CliProviderAuthorizerContext,
    allocator: std.mem.Allocator,
    base_message: []const u8,
    stdout: []const u8,
    stderr: []const u8,
) void {
    var rendered = std.ArrayList(u8){};
    defer rendered.deinit(allocator);

    const command_name = if (ctx.argv.len != 0) ctx.argv[0] else "<unknown>";
    const writer = rendered.writer(allocator);
    writer.print("provider authorizer `{s}`: {s}", .{ command_name, base_message }) catch return;
    appendProviderCommandOutputSnippet(writer, "stderr", stderr) catch return;
    appendProviderCommandOutputSnippet(writer, "stdout", stdout) catch return;

    const message = rendered.toOwnedSlice(allocator) catch return;
    defer allocator.free(message);
    ctx.rpc.recordErrorMessage(message) catch {};
}

fn cliProviderAuthorizerCallback(
    context: *anyopaque,
    allocator: std.mem.Allocator,
    request: client.tx_request_builder.RemoteAuthorizationRequest,
) anyerror!client.tx_request_builder.RemoteAuthorizationResult {
    const ctx = @as(*CliProviderAuthorizerContext, @ptrCast(@alignCast(context)));

    const request_json = try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(request, .{})});
    defer allocator.free(request_json);

    var child = std.process.Child.init(ctx.argv, allocator);
    child.stdin_behavior = .Pipe;
    child.stdout_behavior = .Pipe;
    child.stderr_behavior = .Pipe;

    child.spawn() catch |err| {
        const message = std.fmt.allocPrint(allocator, "failed to start ({s})", .{@errorName(err)}) catch return err;
        defer allocator.free(message);
        recordProviderAuthorizerFailure(ctx, allocator, message, "", "");
        return client.ClientError.RpcError;
    };
    child.waitForSpawn() catch |err| {
        const message = std.fmt.allocPrint(allocator, "failed to initialize ({s})", .{@errorName(err)}) catch return err;
        defer allocator.free(message);
        recordProviderAuthorizerFailure(ctx, allocator, message, "", "");
        return client.ClientError.RpcError;
    };

    if (child.stdin) |stdin| {
        try stdin.writeAll(request_json);
        stdin.close();
        child.stdin = null;
    }

    var stdout = std.ArrayList(u8){};
    defer stdout.deinit(allocator);
    var stderr = std.ArrayList(u8){};
    defer stderr.deinit(allocator);
    child.collectOutput(allocator, &stdout, &stderr, provider_command_output_limit) catch |err| {
        const message = std.fmt.allocPrint(allocator, "failed while reading output ({s})", .{@errorName(err)}) catch return err;
        defer allocator.free(message);
        recordProviderAuthorizerFailure(ctx, allocator, message, stdout.items, stderr.items);
        return if (err == error.OutOfMemory) err else client.ClientError.RpcError;
    };

    const term = child.wait() catch |err| {
        const message = std.fmt.allocPrint(allocator, "failed while waiting for exit ({s})", .{@errorName(err)}) catch return err;
        defer allocator.free(message);
        recordProviderAuthorizerFailure(ctx, allocator, message, stdout.items, stderr.items);
        return if (err == error.OutOfMemory) err else client.ClientError.RpcError;
    };
    switch (term) {
        .Exited => |code| if (code != 0) {
            const message = std.fmt.allocPrint(allocator, "exited with code {}", .{code}) catch return error.OutOfMemory;
            defer allocator.free(message);
            recordProviderAuthorizerFailure(ctx, allocator, message, stdout.items, stderr.items);
            return client.ClientError.RpcError;
        },
        else => {
            recordProviderAuthorizerFailure(ctx, allocator, "terminated unexpectedly", stdout.items, stderr.items);
            return client.ClientError.RpcError;
        },
    }

    var fixed_buffer = std.heap.FixedBufferAllocator.init(&ctx.response_storage);
    return parseRemoteAuthorizationResultJson(fixed_buffer.allocator(), stdout.items) catch |err| {
        if (err == error.OutOfMemory) return err;
        const message = std.fmt.allocPrint(allocator, "returned invalid JSON ({s})", .{@errorName(err)}) catch return error.OutOfMemory;
        defer allocator.free(message);
        recordProviderAuthorizerFailure(ctx, allocator, message, stdout.items, stderr.items);
        return client.ClientError.RpcError;
    };
}

fn ownCliProgrammaticProvider(
    rpc: *client.SuiRpcClient,
    allocator: std.mem.Allocator,
    raw: []const u8,
) !OwnedCliProgrammaticProvider {
    var arena = std.heap.ArenaAllocator.init(allocator);
    errdefer arena.deinit();

    const arena_allocator = arena.allocator();
    const parsed = try std.json.parseFromSlice(std.json.Value, arena_allocator, raw, .{});
    const value = parsed.value;
    if (value != .object) return error.InvalidCli;

    const kind_text = try parseRequiredJsonString(arena_allocator, value.object, &.{"kind"});
    const provider_kind = try parseProviderKind(kind_text);
    const address = try parseOptionalJsonString(arena_allocator, value.object, &.{"address"});
    var session = if (jsonObjectFieldAny(value.object, &.{"session"})) |session_value|
        switch (session_value) {
            .null => client.tx_request_builder.AccountSession{},
            else => try parseAccountSessionFromJsonValue(arena_allocator, session_value),
        }
    else
        client.tx_request_builder.AccountSession{};
    const challenge = if (jsonObjectFieldAny(value.object, &.{"challenge"})) |challenge_value|
        switch (challenge_value) {
            .null => null,
            else => try parseSessionChallengeFromJsonValue(arena_allocator, challenge_value),
        }
    else
        null;
    const action = if (jsonObjectFieldAny(value.object, &.{"action"})) |action_value|
        try parseSessionChallengeActionValue(action_value)
    else
        client.tx_request_builder.SessionChallengeAction.execute;
    const supports_execute = (try parseOptionalJsonBool(value.object, &.{ "supports_execute", "supportsExecute" })) orelse (challenge == null);

    const authorizer_value = jsonObjectFieldAny(value.object, &.{"authorizer"}) orelse return error.InvalidCli;
    if (authorizer_value != .object) return error.InvalidCli;
    const authorizer_argv = (try parseOptionalJsonStringArray(arena_allocator, authorizer_value.object, &.{"exec"})) orelse return error.InvalidCli;
    if (authorizer_argv.len == 0) return error.InvalidCli;
    const authorizer_context = try arena_allocator.create(CliProviderAuthorizerContext);
    authorizer_context.* = .{
        .rpc = rpc,
        .argv = authorizer_argv,
    };

    switch (provider_kind) {
        .remote_signer => {
            if (session.kind == .none) session.kind = .remote_signer;
            return .{
                .arena = arena,
                .provider = .{
                    .remote_signer = .{
                        .address = address,
                        .authorizer = .{
                            .context = authorizer_context,
                            .callback = cliProviderAuthorizerCallback,
                        },
                        .session = session,
                        .session_challenger = if (challenge != null)
                            .{
                                .context = undefined,
                                .callback = cliProviderStaticChallengePromptCallback,
                            }
                        else
                            null,
                        .session_challenge = challenge,
                        .session_action = action,
                        .session_supports_execute = supports_execute,
                    },
                },
            };
        },
        .passkey, .zklogin, .multisig => {
            if (session.kind == .none) {
                session.kind = switch (provider_kind) {
                    .passkey => .passkey,
                    .zklogin => .zklogin,
                    .multisig => .multisig,
                    else => unreachable,
                };
            }

            const account = client.tx_request_builder.FutureWalletAccount{
                .address = address,
                .session = session,
                .authorizer = .{
                    .context = authorizer_context,
                    .callback = cliProviderAuthorizerCallback,
                },
                .session_challenge = challenge,
                .session_action = action,
                .session_supports_execute = supports_execute,
            };

            return .{
                .arena = arena,
                .provider = switch (provider_kind) {
                    .passkey => .{ .passkey = account },
                    .zklogin => .{ .zklogin = account },
                    .multisig => .{ .multisig = account },
                    else => unreachable,
                },
            };
        },
    }
}

fn jsonObjectFieldAny(
    object: std.json.ObjectMap,
    comptime names: []const []const u8,
) ?std.json.Value {
    inline for (names) |name| {
        if (object.get(name)) |value| return value;
    }
    return null;
}

fn parseOptionalJsonString(
    allocator: std.mem.Allocator,
    object: std.json.ObjectMap,
    comptime names: []const []const u8,
) !?[]const u8 {
    const value = jsonObjectFieldAny(object, names) orelse return null;
    return switch (value) {
        .null => null,
        .string => |text| try allocator.dupe(u8, text),
        else => error.InvalidCli,
    };
}

fn parseOptionalJsonBool(
    object: std.json.ObjectMap,
    comptime names: []const []const u8,
) !?bool {
    const value = jsonObjectFieldAny(object, names) orelse return null;
    return switch (value) {
        .null => null,
        .bool => |flag| flag,
        else => error.InvalidCli,
    };
}

fn parseOptionalJsonU64(
    object: std.json.ObjectMap,
    comptime names: []const []const u8,
) !?u64 {
    const value = jsonObjectFieldAny(object, names) orelse return null;
    return switch (value) {
        .null => null,
        .integer => |number| blk: {
            if (number < 0) return error.InvalidCli;
            break :blk @as(u64, @intCast(number));
        },
        .string => |text| try std.fmt.parseInt(u64, text, 10),
        else => error.InvalidCli,
    };
}

fn parseAccountSessionFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.AccountSession {
    if (value != .object) return error.InvalidCli;

    const kind = blk: {
        const kind_value = jsonObjectFieldAny(value.object, &.{"kind"}) orelse break :blk client.tx_request_builder.AccountSessionKind.none;
        break :blk switch (kind_value) {
            .null => client.tx_request_builder.AccountSessionKind.none,
            .string => |text| std.meta.stringToEnum(client.tx_request_builder.AccountSessionKind, text) orelse return error.InvalidCli,
            else => return error.InvalidCli,
        };
    };

    return .{
        .kind = kind,
        .session_id = try parseOptionalJsonString(allocator, value.object, &.{ "session_id", "sessionId" }),
        .user_id = try parseOptionalJsonString(allocator, value.object, &.{ "user_id", "userId" }),
        .expires_at_ms = try parseOptionalJsonU64(value.object, &.{ "expires_at_ms", "expiresAtMs" }),
    };
}

fn parseSessionChallengeResponseFromJsonValue(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !client.tx_request_builder.SessionChallengeResponse {
    if (value != .object) return error.InvalidCli;

    const session = if (jsonObjectFieldAny(value.object, &.{"session"})) |session_value|
        switch (session_value) {
            .null => null,
            else => try parseAccountSessionFromJsonValue(allocator, session_value),
        }
    else
        null;

    return .{
        .session = session,
        .supports_execute = (try parseOptionalJsonBool(value.object, &.{ "supports_execute", "supportsExecute" })) orelse true,
    };
}

fn parseSessionChallengeResponseArg(
    allocator: std.mem.Allocator,
    raw: []const u8,
) !ParsedSessionChallengeResponse {
    var arena = std.heap.ArenaAllocator.init(allocator);
    errdefer arena.deinit();

    const parsed = try std.json.parseFromSlice(std.json.Value, arena.allocator(), raw, .{});
    const response = try parseSessionChallengeResponseFromJsonValue(arena.allocator(), parsed.value);
    return .{
        .arena = arena,
        .response = response,
    };
}

const OwnedStringItems = struct {
    items: std.ArrayListUnmanaged([]const u8) = .{},

    fn deinit(self: *OwnedStringItems, allocator: std.mem.Allocator) void {
        for (self.items.items) |item| allocator.free(item);
        self.items.deinit(allocator);
    }
};

fn tokenStartsSelectedRequest(text: []const u8) bool {
    const trimmed = std.mem.trim(u8, text, " \t\r\n");
    return std.mem.startsWith(u8, trimmed, "select:") or std.mem.startsWith(u8, trimmed, "sel:");
}

fn jsonValueContainsSelectedRequest(value: std.json.Value) bool {
    return switch (value) {
        .string => |text| tokenStartsSelectedRequest(text),
        .array => |array| blk: {
            for (array.items) |item| {
                if (jsonValueContainsSelectedRequest(item)) break :blk true;
            }
            break :blk false;
        },
        .object => |object| blk: {
            var iterator = object.iterator();
            while (iterator.next()) |entry| {
                if (jsonValueContainsSelectedRequest(entry.value_ptr.*)) break :blk true;
            }
            break :blk false;
        },
        else => false,
    };
}

fn moveCallArgsContainSelectedRequestTokens(
    allocator: std.mem.Allocator,
    raw_args: ?[]const u8,
) !bool {
    const args_json = raw_args orelse return false;
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, args_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return error.InvalidCli;
    return jsonValueContainsSelectedRequest(parsed.value);
}

fn hasSelectedMoveCallArgumentRequests(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) !bool {
    if (!hasCompleteTxBuildMoveCallArgs(args)) return false;
    if (hasTxBuildProgrammaticCommands(args)) return false;
    return try moveCallArgsContainSelectedRequestTokens(allocator, args.tx_build_args);
}

fn programmaticCommandsContainSelectedRequestTokens(args: *const cli.ParsedArgs) bool {
    if (args.tx_build_commands) |value| {
        if (std.mem.indexOf(u8, value, "select:") != null or std.mem.indexOf(u8, value, "sel:") != null) return true;
    }
    for (args.tx_build_command_items.items) |item| {
        if (std.mem.indexOf(u8, item, "select:") != null or std.mem.indexOf(u8, item, "sel:") != null) return true;
    }
    return false;
}

fn gasPaymentContainsSelectedRequestToken(args: *const cli.ParsedArgs) bool {
    const value = args.tx_build_gas_payment orelse return false;
    return std.mem.indexOf(u8, value, "select:") != null or std.mem.indexOf(u8, value, "sel:") != null;
}

fn buildMoveCallArgumentTokensFromArgs(
    allocator: std.mem.Allocator,
    raw_args: ?[]const u8,
) !OwnedStringItems {
    var items = OwnedStringItems{};
    errdefer items.deinit(allocator);

    const args_json = raw_args orelse return items;
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, args_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array) return error.InvalidCli;

    for (parsed.value.array.items) |entry| {
        const token = switch (entry) {
            .string => try allocator.dupe(u8, entry.string),
            else => try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(entry, .{})}),
        };
        try items.items.append(allocator, token);
    }

    return items;
}

fn buildSelectedMoveCallInstructionFromArgs(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
) ![]u8 {
    var argument_tokens = try buildMoveCallArgumentTokensFromArgs(allocator, args.tx_build_args);
    defer argument_tokens.deinit(allocator);

    const sender = try resolvedTxBuildSenderFromArgs(allocator, args);
    defer if (sender) |value| allocator.free(value);

    var values = try rpc.resolveArgumentValuesFromTokensWithDefaultOwner(allocator, argument_tokens.items.items, sender);
    defer values.deinit(allocator);

    const arguments_json = try client.tx_request_builder.buildArgumentValueArray(allocator, values.slice());
    defer allocator.free(arguments_json);

    var out = std.ArrayList(u8){};
    errdefer out.deinit(allocator);
    try writeMoveCallInstruction(
        allocator,
        out.writer(allocator),
        args.tx_build_package.?,
        args.tx_build_module.?,
        args.tx_build_function.?,
        args.tx_build_type_args,
        arguments_json,
    );
    return out.toOwnedSlice(allocator);
}

fn commandRequestConfigFromOptions(
    options: client.tx_request_builder.ProgrammaticRequestOptions,
    sender: ?[]const u8,
) client.tx_request_builder.CommandRequestConfig {
    return .{
        .sender = sender,
        .gas_budget = options.gas_budget,
        .gas_price = options.gas_price,
        .gas_payment_json = options.gas_payment_json,
        .expiration_json = options.expiration_json,
        .policy_json = options.policy_json,
        .delegated_session_json = options.delegated_session_json,
        .signatures = options.signatures,
        .options_json = options.options_json,
        .wait_for_confirmation = options.wait_for_confirmation,
        .confirm_timeout_ms = options.confirm_timeout_ms,
        .confirm_poll_ms = options.confirm_poll_ms,
    };
}

fn ownProgrammaticExecutionOptionsFromArgs(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    signatures: []const []const u8,
) !OwnedProgrammaticExecutionOptions {
    var owned = OwnedProgrammaticExecutionOptions{
        .options = @import("./tx_pipeline.zig").programmaticRequestOptionsFromArgs(args, signatures),
    };
    errdefer owned.deinit(allocator);

    var delegated_session = try resolveDelegatedSessionArtifactSummary(allocator, args);
    defer if (delegated_session) |*value| value.deinit(allocator);

    owned.policy_json = try buildMergedWalletPolicyJsonWithBase(
        allocator,
        if (delegated_session) |value| value.policy_json else null,
        args,
    );
    owned.options.policy_json = owned.policy_json;

    if (delegated_session != null or args.request_delegated_session_json != null) {
        var output = std.ArrayList(u8){};
        errdefer output.deinit(allocator);
        try writeDelegatedSessionArtifactMetadata(
            output.writer(allocator),
            if (delegated_session) |*value| value else null,
            args.request_delegated_session_json,
        );
        owned.delegated_session_json = try output.toOwnedSlice(allocator);
        owned.options.delegated_session_json = owned.delegated_session_json;
    }

    return owned;
}

fn runSelectedProgrammaticAction(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    signatures: []const []const u8,
    provider: ?client.tx_request_builder.AccountProvider,
    action: client.rpc_client.ProgrammaticClientAction,
) !client.rpc_client.ProgrammaticClientActionResult {
    var owned_options = try ownProgrammaticExecutionOptionsFromArgs(allocator, args, signatures);
    defer owned_options.deinit(allocator);
    const options = owned_options.options;
    const resolved_sender = try resolvedTxBuildSenderFromArgsOrProgrammaticProvider(
        allocator,
        args,
        provider,
    );
    defer if (resolved_sender) |value| allocator.free(value);
    const sender = resolved_sender;
    const config = commandRequestConfigFromOptions(options, sender);

    if (args.tx_build_auto_gas_payment) {
        return try rpc.runCommandsWithAutoGasPaymentWithAccountProvider(
            allocator,
            options.source,
            config,
            provider orelse .none,
            args.tx_build_gas_payment_min_balance,
            action,
        );
    }

    return try rpc.runCommandsResolvingSelectedArgumentTokensWithAccountProvider(
        allocator,
        options.source,
        config,
        provider orelse .none,
        action,
    );
}

fn hasKeystoreBackedSignerSource(args: *const cli.ParsedArgs) bool {
    return args.signers.items.len != 0 or args.from_keystore;
}

fn hasRealBuilderSignerSource(args: *const cli.ParsedArgs) bool {
    return args.signatures.items.len != 0 or hasKeystoreBackedSignerSource(args);
}

fn resolvedLocalBuilderGasPaymentJson(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    sender: []const u8,
    effective_gas_budget: ?u64,
    implicit_auto_gas_payment_min_balance: ?u64,
    excluded_object_ids: []const []u8,
) !?[]u8 {
    return try rpc.ownResolvedGasPaymentJsonWithDefaultOwnerAndExclusions(
        allocator,
        args.tx_build_gas_payment,
        sender,
        if (args.tx_build_auto_gas_payment)
            args.tx_build_gas_payment_min_balance orelse effective_gas_budget orelse args.tx_build_gas_budget orelse 1
        else
            implicit_auto_gas_payment_min_balance,
        excluded_object_ids,
    );
}

const provisional_auto_gas_budget: u64 = 100_000_000;
const auto_gas_budget_min_buffer: u64 = 1_000;
const auto_gas_budget_buffer_divisor: u64 = 5;

fn estimatedGasBudgetFromInsights(
    insights: client.tx_result.OwnedExecutionInsights,
) !u64 {
    const computation_cost = insights.gas_summary.computation_cost orelse 0;
    const storage_cost = insights.gas_summary.storage_cost orelse 0;
    const non_refundable_storage_fee = insights.gas_summary.non_refundable_storage_fee orelse 0;

    const gross_cost = try std.math.add(
        u64,
        try std.math.add(u64, computation_cost, storage_cost),
        non_refundable_storage_fee,
    );
    if (gross_cost == 0) return error.InvalidResponse;

    const buffer = @max(auto_gas_budget_min_buffer, gross_cost / auto_gas_budget_buffer_divisor);
    return try std.math.add(u64, gross_cost, buffer);
}

fn resolvedLocalBuilderGasPrice(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
) !?u64 {
    _ = allocator;
    return try rpc.resolveEffectiveGasPrice(args.tx_build_gas_price, args.signatures.items.len != 0);
}

fn extractGasObjectIdFromGasPaymentJson(
    allocator: std.mem.Allocator,
    gas_payment_json: []const u8,
) !?[]u8 {
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, gas_payment_json, .{});
    defer parsed.deinit();
    if (parsed.value != .array or parsed.value.array.items.len == 0) return null;

    const first = parsed.value.array.items[0];
    if (first != .object) return null;
    const object_id = first.object.get("objectId") orelse return null;
    if (object_id != .string or object_id.string.len == 0) return null;
    return try allocator.dupe(u8, object_id.string);
}

fn resolvedUnsafeMoveCallGasObjectId(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    sender: []const u8,
) !?[]u8 {
    if (try rpc.resolveSelectedGasPaymentJsonWithDefaultOwner(
        allocator,
        args.tx_build_gas_payment,
        sender,
    )) |resolved_gas_payment_json| {
        defer allocator.free(resolved_gas_payment_json);
        return try extractGasObjectIdFromGasPaymentJson(allocator, resolved_gas_payment_json);
    }

    if (args.tx_build_auto_gas_payment) {
        const gas_payment_json = try rpc.selectGasPaymentJson(
            allocator,
            sender,
            args.tx_build_gas_payment_min_balance orelse args.tx_build_gas_budget orelse 1,
        ) orelse return error.SelectionNotFound;
        defer allocator.free(gas_payment_json);
        return try extractGasObjectIdFromGasPaymentJson(allocator, gas_payment_json);
    }

    if (args.tx_build_gas_payment) |value| {
        return try extractGasObjectIdFromGasPaymentJson(allocator, value);
    }

    return null;
}

fn resolvedUnsafeMoveCallSender(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
) !?[]const u8 {
    if (try @import("./tx_pipeline.zig").resolvedTxBuildSenderFromArgs(allocator, args)) |sender| {
        return @as(?[]const u8, sender);
    }

    _ = rpc;
    return try client.SuiRpcClient.inferSelectedRequestOwnerFromOptions(
        allocator,
        programmaticRequestOptionsFromArgs(args, &.{}),
    );
}

fn resolvedTxBuildSenderFromArgsOrProgrammaticProvider(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    provider: ?client.tx_request_builder.AccountProvider,
) !?[]const u8 {
    if (try resolvedTxBuildSenderFromArgs(allocator, args)) |sender| {
        return sender;
    }
    if (provider) |value| {
        return try resolveSenderFromProgrammaticProvider(allocator, value);
    }
    return null;
}

fn resolveSenderFromKeystoreContentsAccount(
    allocator: std.mem.Allocator,
    account: client.tx_request_builder.KeystoreContentsAccount,
) !?[]const u8 {
    if (account.preparation.signer_selectors.len > 0) {
        var had_resolver_input = false;
        for (account.preparation.signer_selectors) |selector| {
            if (selector.len == 0) continue;
            had_resolver_input = true;
            if (try client.keystore.resolveAddressFromKeystoreContents(allocator, account.contents, selector)) |value| {
                return value;
            }
        }
        if (had_resolver_input) return error.InvalidCli;
        return null;
    }
    if (account.preparation.from_keystore) {
        return try client.keystore.resolveFirstAddressFromKeystoreContents(allocator, account.contents);
    }
    return null;
}

fn resolveSenderFromDefaultKeystoreAccount(
    allocator: std.mem.Allocator,
    account: client.tx_request_builder.DefaultKeystoreAccount,
) !?[]const u8 {
    if (account.preparation.signer_selectors.len > 0) {
        var had_resolver_input = false;
        for (account.preparation.signer_selectors) |selector| {
            if (selector.len == 0) continue;
            had_resolver_input = true;
            if (try client.keystore.resolveAddressBySelector(allocator, selector)) |value| {
                return value;
            }
        }
        if (had_resolver_input) return error.InvalidCli;
        return null;
    }
    if (account.preparation.from_keystore) {
        return try client.keystore.resolveFirstAddressFromDefaultKeystore(allocator);
    }
    return null;
}

fn resolveSenderFromProgrammaticProvider(
    allocator: std.mem.Allocator,
    provider: client.tx_request_builder.AccountProvider,
) !?[]const u8 {
    return switch (provider) {
        .none => null,
        .direct_signatures => |account| if (account.sender) |sender|
            try allocator.dupe(u8, sender)
        else
            null,
        .keystore_contents => |account| try resolveSenderFromKeystoreContentsAccount(allocator, account),
        .default_keystore => |account| try resolveSenderFromDefaultKeystoreAccount(allocator, account),
        .remote_signer => |account| if (account.address) |sender|
            try allocator.dupe(u8, sender)
        else
            null,
        .zklogin => |account| if (account.address) |sender|
            try allocator.dupe(u8, sender)
        else
            null,
        .passkey => |account| if (account.address) |sender|
            try allocator.dupe(u8, sender)
        else
            null,
        .multisig => |account| if (account.address) |sender|
            try allocator.dupe(u8, sender)
        else
            null,
    };
}

fn defaultSenderFromProgrammaticProvider(
    provider: client.tx_request_builder.AccountProvider,
) ?[]const u8 {
    return switch (provider) {
        .direct_signatures => |account| account.sender,
        .remote_signer => |account| account.address,
        .zklogin => |account| account.address,
        .passkey => |account| account.address,
        .multisig => |account| account.address,
        else => null,
    };
}

fn allowReferenceGasPriceFallbackForLocalProviderPath(
    provider: client.tx_request_builder.AccountProvider,
) bool {
    return switch (provider) {
        .default_keystore,
        .direct_signatures,
        .remote_signer,
        .zklogin,
        .passkey,
        .multisig,
        => true,
        else => false,
    };
}

fn supportsImplicitGasPaymentFallbackForLocalProviderPath(
    provider: client.tx_request_builder.AccountProvider,
) bool {
    return switch (provider) {
        .default_keystore,
        .direct_signatures,
        .remote_signer,
        .zklogin,
        .passkey,
        .multisig,
        => true,
        else => false,
    };
}

fn allowReferenceGasPriceFallbackForLocalSignerPath(
    args: *const cli.ParsedArgs,
) bool {
    return hasRealBuilderSignerSource(args);
}

fn implicitLocalGasPaymentFallbackMinBalance(
    args: *const cli.ParsedArgs,
    provider: ?client.tx_request_builder.AccountProvider,
) ?u64 {
    const has_supported_local_signer_source = if (provider) |value|
        supportsImplicitGasPaymentFallbackForLocalProviderPath(value)
    else
        hasRealBuilderSignerSource(args) or args.tx_build_sender != null;
    if (!has_supported_local_signer_source) return null;
    if (args.tx_build_gas_budget == null) return null;
    if (args.tx_build_auto_gas_budget or args.tx_build_auto_gas_payment) return null;
    if (args.tx_build_gas_payment != null) return null;
    return args.tx_build_gas_budget;
}

fn resolvedUnsafeMoveCallArgumentsJson(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    sender: []const u8,
) !?[]u8 {
    if (!(try hasSelectedMoveCallArgumentRequests(allocator, args))) return null;

    var argument_tokens = try buildMoveCallArgumentTokensFromArgs(allocator, args.tx_build_args);
    defer argument_tokens.deinit(allocator);

    var values = try rpc.resolveArgumentValuesFromTokensWithDefaultOwner(
        allocator,
        argument_tokens.items.items,
        sender,
    );
    defer values.deinit(allocator);

    return try client.tx_request_builder.buildArgumentValueArray(allocator, values.slice());
}

const OwnedUnsafeCommandSource = struct {
    source: tx_builder.CommandSource,
    owned_json: ?[]u8 = null,

    fn deinit(self: *OwnedUnsafeCommandSource, allocator: std.mem.Allocator) void {
        if (self.owned_json) |value| allocator.free(value);
    }
};

fn resolvedUnsafeCommandSource(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    sender: []const u8,
) !OwnedUnsafeCommandSource {
    if (hasCompleteTxBuildMoveCallArgs(args) and !hasTxBuildProgrammaticCommands(args)) {
        const resolved_arguments_json = try resolvedUnsafeMoveCallArgumentsJson(allocator, rpc, args, sender);
        if (resolved_arguments_json) |value| {
            return .{
                .source = .{
                    .move_call = .{
                        .package_id = args.tx_build_package.?,
                        .module = args.tx_build_module.?,
                        .function_name = args.tx_build_function.?,
                        .type_args = args.tx_build_type_args,
                        .arguments = value,
                    },
                },
                .owned_json = value,
            };
        }
        return .{ .source = commandSourceFromArgs(args) };
    }

    const maybe_resolved_commands_json = try rpc.resolveSelectedArgumentTokensInCommandSourceWithDefaultOwner(
        allocator,
        commandSourceFromArgs(args),
        sender,
    );
    if (maybe_resolved_commands_json) |value| {
        return .{
            .source = .{ .commands_json = value },
            .owned_json = value,
        };
    }

    return .{ .source = commandSourceFromArgs(args) };
}

fn buildUnsafeCommandSourceTxBytes(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
) ![]u8 {
    const sender = try resolvedUnsafeMoveCallSender(allocator, rpc, args) orelse return error.InvalidCli;
    defer allocator.free(sender);

    var owned_source = try resolvedUnsafeCommandSource(allocator, rpc, args, sender);
    defer owned_source.deinit(allocator);

    const gas_object_id = try resolvedUnsafeMoveCallGasObjectId(allocator, rpc, args, sender);
    defer if (gas_object_id) |value| allocator.free(value);
    const gas_budget = args.tx_build_gas_budget orelse if (args.tx_build_auto_gas_budget)
        provisional_auto_gas_budget
    else
        return error.InvalidCli;

    return try rpc.buildCommandSourceTxBytes(
        allocator,
        sender,
        owned_source.source,
        gas_object_id,
        gas_budget,
    );
}

fn buildLocalCommandSourceExecutePayload(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    provider: ?client.tx_request_builder.AccountProvider,
) !?[]u8 {
    var owned_options = try ownProgrammaticExecutionOptionsFromArgs(allocator, args, args.signatures.items);
    defer owned_options.deinit(allocator);
    const options = owned_options.options;

    const implicit_auto_gas_payment_min_balance = implicitLocalGasPaymentFallbackMinBalance(args, provider);

    const allow_reference_gas_price_fallback = if (provider) |value|
        allowReferenceGasPriceFallbackForLocalProviderPath(value)
    else
        allowReferenceGasPriceFallbackForLocalSignerPath(args);

    var local = ownLocalCommandSourceBuildContext(
        allocator,
        rpc,
        args,
        provider,
        true,
        allow_reference_gas_price_fallback,
        false,
        implicit_auto_gas_payment_min_balance,
    ) catch |err| switch (err) {
        error.InvalidCli => return null,
        else => return err,
    } orelse return null;
    defer local.deinit(allocator);

    if (args.signatures.items.len != 0) {
        return rpc.buildLocalProgrammableTransactionExecutePayloadFromCommandSourceWithSignatures(
            allocator,
            local.source,
            local.sender,
            local.gas_payment_json,
            local.gas_price,
            local.gas_budget,
            null,
            args.signatures.items,
            options.options_json,
        ) catch |err| switch (err) {
            error.InvalidCli => null,
            else => err,
        };
    }

    if (provider) |value| {
        return rpc.buildLocalProgrammableTransactionExecutePayloadFromCommandSourceWithAccountProvider(
            allocator,
            local.source,
            local.sender,
            local.gas_payment_json,
            local.gas_price,
            local.gas_budget,
            null,
            options.policy_json,
            options.delegated_session_json,
            options.options_json,
            value,
        ) catch |err| switch (err) {
            error.InvalidCli => null,
            error.UnsupportedAccountProvider => null,
            else => err,
        };
    }

    return rpc.buildLocalProgrammableTransactionExecutePayloadFromCommandSourceFromDefaultKeystore(
        allocator,
        local.source,
        local.sender,
        local.gas_payment_json,
        local.gas_price,
        local.gas_budget,
        null,
        options.options_json,
        .{
            .signer_selectors = args.signers.items,
            .from_keystore = args.from_keystore,
            .infer_sender_from_signers = true,
        },
    ) catch |err| switch (err) {
        error.InvalidCli => null,
        else => err,
    };
}

fn buildLocalCommandSourceTxBytes(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    provider: ?client.tx_request_builder.AccountProvider,
) !?[]u8 {
    const implicit_auto_gas_payment_min_balance = implicitLocalGasPaymentFallbackMinBalance(args, provider);
    var local = ownLocalCommandSourceBuildContext(
        allocator,
        rpc,
        args,
        provider,
        false,
        true,
        false,
        implicit_auto_gas_payment_min_balance,
    ) catch |err| switch (err) {
        error.InvalidCli => return null,
        else => return err,
    } orelse return null;
    defer local.deinit(allocator);

    return rpc.buildLocalProgrammableTransactionTxBytesFromCommandSource(
        allocator,
        local.source,
        local.sender,
        local.gas_payment_json,
        local.gas_price,
        local.gas_budget,
        null,
    ) catch |err| switch (err) {
