                        },
                    },
                },
            .owned_objects = if (args.account_resources_all)
                .{
                    .all = .{
                        .owner = owner,
                        .request = .{
                            .filter = ownedObjectsFilterFromArgs(args),
                            .options = objectReadOptionsFromArgs(args),
                            .limit = args.account_resources_limit,
                        },
                    },
                }
            else
                .{
                    .page = .{
                        .owner = owner,
                        .request = .{
                            .filter = ownedObjectsFilterFromArgs(args),
