    if (summary.registry_path) |value| try writer.print("wallet_sessions_path: {s}\n", .{value});
    if (summary.active_selector) |value| try writer.print("active_wallet: {s}\n", .{value});
    try writer.print("active_wallet_match: {any}\n", .{summary.active_wallet_match});
}

fn formatWalletPolicyInspectSummary(
    writer: anytype,
    summary: *const OwnedWalletPolicyInspectSummary,
    json_output: bool,
    pretty: bool,
) !void {
    if (json_output or pretty) {
        try printStructuredJson(writer, summary.*, pretty);
        return;
    }

    try writer.print("policy source: {s}\n", .{summary.source_kind});
    if (summary.selector) |value| try writer.print("selector: {s}\n", .{value});
    if (summary.session_id) |value| try writer.print("session_id: {s}\n", .{value});
    if (summary.wallet_selector) |value| try writer.print("wallet_selector: {s}\n", .{value});
    if (summary.address) |value| try writer.print("address: {s}\n", .{value});
    if (summary.session_kind) |value| try writer.print("session_kind: {s}\n", .{value});
    if (summary.state) |value| try writer.print("state: {s}\n", .{value});
    if (summary.registry_path) |value| try writer.print("wallet_sessions_path: {s}\n", .{value});
    if (summary.active_selector) |value| try writer.print("active_wallet: {s}\n", .{value});
    try writer.print("active_wallet_match: {any}\n", .{summary.active_wallet_match});
    try writer.writeAll("policy: ");
    if (summary.policy_json) |value| {
        try writer.print("{s}\n", .{value});
    } else {
        try writer.writeAll("null\n");
    }
}

fn duplicateOptionalOwned(allocator: std.mem.Allocator, value: ?[]const u8) !?[]u8 {
    const slice = value orelse return null;
    return try allocator.dupe(u8, slice);
}

fn duplicateRequired(allocator: std.mem.Allocator, value: []const u8) ![]u8 {
    return try allocator.dupe(u8, value);
}

fn walletRegistryStateMatchesSelectorOrAddress(
    selector_or_address: []const u8,
    selector: []const u8,
    address: []const u8,
) bool {
    return std.mem.eql(u8, selector_or_address, selector) or std.mem.eql(u8, selector_or_address, address);
}

fn findConnectedExternalWalletIndex(
    registry: *const wallet_registry.OwnedWalletRegistry,
    selector_or_address: []const u8,
) ?usize {
    for (registry.external_wallets, 0..) |entry, index| {
        if (!std.mem.eql(u8, entry.state, "connected")) continue;
        if (walletRegistryStateMatchesSelectorOrAddress(selector_or_address, entry.selector, entry.address)) return index;
        if (entry.label) |label| {
            if (std.mem.eql(u8, selector_or_address, label)) return index;
        }
    }
    return null;
}

fn findExternalWalletIndexAnyState(
    registry: *const wallet_registry.OwnedWalletRegistry,
    selector_or_address: []const u8,
) ?usize {
    for (registry.external_wallets, 0..) |entry, index| {
        if (walletRegistryStateMatchesSelectorOrAddress(selector_or_address, entry.selector, entry.address)) return index;
        if (entry.label) |label| {
            if (std.mem.eql(u8, selector_or_address, label)) return index;
        }
    }
    return null;
}

fn findActivePasskeyIndex(
    registry: *const wallet_registry.OwnedWalletRegistry,
    selector_or_address: []const u8,
) ?usize {
    for (registry.passkey_credentials, 0..) |entry, index| {
        if (!std.mem.eql(u8, entry.state, "active")) continue;
        if (walletRegistryStateMatchesSelectorOrAddress(selector_or_address, entry.selector, entry.address)) return index;
        if (std.mem.eql(u8, selector_or_address, entry.credential_id)) return index;
        if (entry.label) |label| {
            if (std.mem.eql(u8, selector_or_address, label)) return index;
        }
    }
    return null;
}

fn findPasskeyIndexAnyState(
    registry: *const wallet_registry.OwnedWalletRegistry,
    selector_or_address: []const u8,
) ?usize {
    for (registry.passkey_credentials, 0..) |entry, index| {
        if (walletRegistryStateMatchesSelectorOrAddress(selector_or_address, entry.selector, entry.address)) return index;
        if (std.mem.eql(u8, selector_or_address, entry.credential_id)) return index;
        if (entry.label) |label| {
            if (std.mem.eql(u8, selector_or_address, label)) return index;
        }
    }
    return null;
}

fn walletSessionMatchesSelectorOrAddressOrId(
    entry: *const wallet_session_registry.OwnedWalletSessionEntry,
    selector_or_address: []const u8,
) bool {
    if (std.mem.eql(u8, selector_or_address, entry.selector)) return true;
    if (entry.label) |label| {
        if (std.mem.eql(u8, selector_or_address, label)) return true;
    }
    if (entry.address) |address| {
        if (std.mem.eql(u8, selector_or_address, address)) return true;
    }
    return std.mem.eql(u8, selector_or_address, entry.session_id);
}

fn findWalletSessionIndexAnyState(
    registry: *const wallet_session_registry.OwnedWalletSessionRegistry,
    selector_or_address: []const u8,
) ?usize {
    for (registry.entries, 0..) |entry, index| {
        if (walletSessionMatchesSelectorOrAddressOrId(&entry, selector_or_address)) return index;
    }
    return null;
}

fn sessionEntryMatchesActiveWalletSelector(
    active_selector: ?[]const u8,
    entry: *const wallet_session_registry.OwnedWalletSessionEntry,
) bool {
    if (entry.wallet_selector) |wallet_selector| {
        if (sameWalletSelectorOrAddress(active_selector, wallet_selector, entry.address)) return true;
    }
    return sameWalletSelectorOrAddress(active_selector, entry.selector, entry.address);
}

fn validateDelegatedSessionEntryUsable(
    entry: *const wallet_session_registry.OwnedWalletSessionEntry,
) !void {
    if (!std.mem.eql(u8, entry.state, "active")) return error.InvalidCli;
    if (entry.expires_at_ms) |expires_at_ms| {
        if (expires_at_ms <= std.time.milliTimestamp()) return error.InvalidCli;
    }
}

fn loadDelegatedSessionArtifactSummaryFromRegistry(
    allocator: std.mem.Allocator,
    selector_or_address: []const u8,
) !OwnedDelegatedSessionArtifactSummary {
    const registry_path = try wallet_session_registry.resolveDefaultWalletSessionRegistryPath(allocator) orelse return error.InvalidCli;
    defer allocator.free(registry_path);

    var registry = try wallet_session_registry.loadDefaultWalletSessionRegistry(allocator);
    defer registry.deinit(allocator);

    const index = findWalletSessionIndexAnyState(&registry, selector_or_address) orelse return error.InvalidCli;
    const entry = &registry.entries[index];
    try validateDelegatedSessionEntryUsable(entry);

    const active_selector = try wallet_state.resolveActiveSelector(allocator);
    defer if (active_selector) |value| allocator.free(value);

    return .{
        .source_kind = try allocator.dupe(u8, "session_registry"),
        .selector = try allocator.dupe(u8, entry.selector),
        .label = try duplicateOptionalSlice(allocator, entry.label),
        .wallet_selector = try duplicateOptionalSlice(allocator, entry.wallet_selector),
        .address = try duplicateOptionalSlice(allocator, entry.address),
        .session_id = try allocator.dupe(u8, entry.session_id),
        .session_kind = try duplicateOptionalSlice(allocator, entry.session_kind),
        .state = try allocator.dupe(u8, entry.state),
        .expires_at_ms = entry.expires_at_ms,
        .active_wallet_match = sessionEntryMatchesActiveWalletSelector(active_selector, entry),
        .registry_path = try allocator.dupe(u8, registry_path),
        .policy_json = try duplicateOptionalSlice(allocator, entry.policy_json),
    };
}

fn parseEmbeddedDelegatedSessionArtifactSummary(
    allocator: std.mem.Allocator,
    raw: []const u8,
) !OwnedDelegatedSessionArtifactSummary {
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, raw, .{});
    defer parsed.deinit();
    if (parsed.value != .object) return error.InvalidCli;

    const source_kind = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{ "source_kind", "sourceKind" })) |value|
        @constCast(value)
    else
        try allocator.dupe(u8, "embedded");
    errdefer allocator.free(source_kind);
    const selector = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{"selector"})) |value|
        @constCast(value)
    else
        try allocator.alloc(u8, 0);
    errdefer allocator.free(selector);
    const label = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{"label"})) |value|
        @constCast(value)
    else
        null;
    errdefer if (label) |value| allocator.free(value);
    const wallet_selector = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{ "wallet_selector", "walletSelector" })) |value|
        @constCast(value)
    else
        null;
    errdefer if (wallet_selector) |value| allocator.free(value);
    const address = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{"address"})) |value|
        @constCast(value)
    else
        null;
    errdefer if (address) |value| allocator.free(value);
    const session_id = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{ "session_id", "sessionId" })) |value|
        @constCast(value)
    else
        return error.InvalidCli;
    errdefer allocator.free(session_id);
    const session_kind = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{ "session_kind", "sessionKind" })) |value|
        @constCast(value)
    else
        null;
    errdefer if (session_kind) |value| allocator.free(value);
    const state = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{"state"})) |value|
        @constCast(value)
    else
        try allocator.dupe(u8, "active");
    errdefer allocator.free(state);
    const expires_at_ms = if (try parseOptionalJsonU64(parsed.value.object, &.{ "expires_at_ms", "expiresAtMs" })) |value|
        @as(i64, @intCast(value))
    else
        null;
    const active_wallet_match = (try parseOptionalJsonBool(parsed.value.object, &.{ "active_wallet_match", "activeWalletMatch" })) orelse false;
    const registry_path = if (try parseOptionalJsonString(allocator, parsed.value.object, &.{ "registry_path", "registryPath" })) |value|
        @constCast(value)
    else
        null;
    errdefer if (registry_path) |value| allocator.free(value);

    return .{
        .source_kind = source_kind,
        .selector = selector,
        .label = label,
        .wallet_selector = wallet_selector,
        .address = address,
        .session_id = session_id,
        .session_kind = session_kind,
        .state = state,
        .expires_at_ms = expires_at_ms,
        .active_wallet_match = active_wallet_match,
        .registry_path = registry_path,
        .policy_json = null,
    };
}

fn resolveDelegatedSessionArtifactSummary(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) !?OwnedDelegatedSessionArtifactSummary {
    if (args.request_session_selector) |selector_or_address| {
        return try loadDelegatedSessionArtifactSummaryFromRegistry(allocator, selector_or_address);
    }

    const embedded_json = args.request_delegated_session_json orelse return null;
    var embedded = try parseEmbeddedDelegatedSessionArtifactSummary(allocator, embedded_json);
    var owns_embedded = true;
    errdefer if (owns_embedded) embedded.deinit(allocator);

    if (std.mem.eql(u8, embedded.source_kind, "session_registry") and embedded.selector.len != 0) {
        const selector = try allocator.dupe(u8, embedded.selector);
        defer allocator.free(selector);
        const reloaded = loadDelegatedSessionArtifactSummaryFromRegistry(allocator, selector) catch |err| switch (err) {
            error.InvalidCli => null,
            else => return err,
        };
        if (reloaded) |value| {
            embedded.deinit(allocator);
            owns_embedded = false;
            return value;
        }
    }

    return embedded;
}

fn delegatedSessionAccountKind(
    summary: *const OwnedDelegatedSessionArtifactSummary,
) !client.tx_request_builder.AccountSessionKind {
    if (summary.session_kind) |session_kind| {
        if (std.mem.eql(u8, session_kind, "local_signer") or std.mem.eql(u8, session_kind, "local_keystore")) {
            return .local_keystore;
        }
        if (std.mem.eql(u8, session_kind, "passkey")) return .passkey;
        if (std.mem.eql(u8, session_kind, "external_wallet") or std.mem.eql(u8, session_kind, "remote_signer")) {
            return .remote_signer;
        }
        if (std.mem.eql(u8, session_kind, "zklogin")) return .zklogin;
        if (std.mem.eql(u8, session_kind, "multisig")) return .multisig;
        return error.InvalidCli;
    }

    if (summary.wallet_selector) |wallet_selector| {
        if (std.mem.startsWith(u8, wallet_selector, "passkey:")) return .passkey;
        if (std.mem.startsWith(u8, wallet_selector, "external:")) return .remote_signer;
    }
    if (std.mem.startsWith(u8, summary.selector, "passkey:")) return .passkey;
    if (std.mem.startsWith(u8, summary.selector, "external:")) return .remote_signer;
    return .local_keystore;
}

fn delegatedSessionAccountSession(
    summary: *const OwnedDelegatedSessionArtifactSummary,
) !client.tx_request_builder.AccountSession {
    return .{
        .kind = try delegatedSessionAccountKind(summary),
        .session_id = summary.session_id,
        .expires_at_ms = if (summary.expires_at_ms) |value| @as(u64, @intCast(value)) else null,
    };
}

fn delegatedSessionLocalSignerSelectors(
    allocator: std.mem.Allocator,
    summary: *const OwnedDelegatedSessionArtifactSummary,
) ![]const []const u8 {
    const signer_selector = if (summary.wallet_selector) |wallet_selector|
        if (!std.mem.startsWith(u8, wallet_selector, "passkey:") and !std.mem.startsWith(u8, wallet_selector, "external:"))
            wallet_selector
        else
            (summary.address orelse return error.InvalidCli)
    else
        (summary.address orelse return error.InvalidCli);

    const selectors = try allocator.alloc([]const u8, 1);
    selectors[0] = signer_selector;
    return selectors;
}

fn validateDelegatedSessionProviderAddress(
    expected_address: ?[]const u8,
    provider_address: ?[]const u8,
) !?[]const u8 {
    if (expected_address == null) return provider_address;
    if (provider_address == null) return expected_address;
    if (!std.mem.eql(u8, expected_address.?, provider_address.?)) return error.InvalidCli;
    return provider_address;
}

fn applyDelegatedSessionToProgrammaticProvider(
    summary: *const OwnedDelegatedSessionArtifactSummary,
    provider: client.tx_request_builder.AccountProvider,
) !client.tx_request_builder.AccountProvider {
    const session = try delegatedSessionAccountSession(summary);
    return switch (provider) {
        .none => error.InvalidCli,
        .direct_signatures => error.InvalidCli,
        .keystore_contents => |account| blk: {
            if (session.kind != .local_keystore) return error.InvalidCli;
            var updated = account;
            updated.session = session;
            break :blk .{ .keystore_contents = updated };
        },
        .default_keystore => |account| blk: {
            if (session.kind != .local_keystore) return error.InvalidCli;
            var updated = account;
            updated.session = session;
            break :blk .{ .default_keystore = updated };
        },
        .remote_signer => |account| blk: {
            if (session.kind != .remote_signer) return error.InvalidCli;
            var updated = account;
            updated.address = try validateDelegatedSessionProviderAddress(summary.address, account.address);
            updated.session = session;
            break :blk .{ .remote_signer = updated };
        },
        .passkey => |account| blk: {
            if (session.kind != .passkey) return error.InvalidCli;
            var updated = account;
            updated.address = try validateDelegatedSessionProviderAddress(summary.address, account.address);
            updated.session = session;
            break :blk .{ .passkey = updated };
        },
        .zklogin => |account| blk: {
            if (session.kind != .zklogin) return error.InvalidCli;
            var updated = account;
            updated.address = try validateDelegatedSessionProviderAddress(summary.address, account.address);
            updated.session = session;
            break :blk .{ .zklogin = updated };
        },
        .multisig => |account| blk: {
            if (session.kind != .multisig) return error.InvalidCli;
            var updated = account;
            updated.address = try validateDelegatedSessionProviderAddress(summary.address, account.address);
            updated.session = session;
            break :blk .{ .multisig = updated };
        },
    };
}

fn usesDelegatedSessionExecutionFlow(command: cli.Command) bool {
    return command == .wallet_intent_send or
        command == .request_sign or
        command == .request_send;
}

fn ownProgrammaticProviderWithDelegatedSession(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    provider: ?client.tx_request_builder.AccountProvider,
) !OwnedProgrammaticProviderWithDelegatedSession {
    var resolved: OwnedProgrammaticProviderWithDelegatedSession = .{
        .provider = provider,
    };
    errdefer resolved.deinit(allocator);

    if (!usesDelegatedSessionExecutionFlow(args.command)) return resolved;

    resolved.delegated_session = try resolveDelegatedSessionArtifactSummary(allocator, args);
    if (resolved.delegated_session == null) return resolved;

    if (provider) |value| {
        resolved.provider = try applyDelegatedSessionToProgrammaticProvider(&resolved.delegated_session.?, value);
        return resolved;
    }

    const session = try delegatedSessionAccountSession(&resolved.delegated_session.?);
    if (session.kind != .local_keystore) return error.InvalidCli;

    resolved.local_signer_selectors = try delegatedSessionLocalSignerSelectors(allocator, &resolved.delegated_session.?);
    resolved.provider = .{
        .default_keystore = .{
            .preparation = .{
                .signer_selectors = resolved.local_signer_selectors.?,
                .from_keystore = false,
                .infer_sender_from_signers = true,
            },
            .session = session,
        },
    };
    return resolved;
}

fn writeDelegatedSessionArtifactMetadata(
    writer: anytype,
    session: ?*const OwnedDelegatedSessionArtifactSummary,
    embedded_json: ?[]const u8,
) !void {
    if (session) |value| {
        try writer.writeAll("{");
        try writer.writeAll("\"source_kind\":");
        try writer.print("{f}", .{std.json.fmt(value.source_kind, .{})});
        try writer.writeAll(",\"selector\":");
        try writer.print("{f}", .{std.json.fmt(value.selector, .{})});
        try writer.writeAll(",\"label\":");
        if (value.label) |label| {
            try writer.print("{f}", .{std.json.fmt(label, .{})});
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",\"wallet_selector\":");
        if (value.wallet_selector) |wallet_selector| {
            try writer.print("{f}", .{std.json.fmt(wallet_selector, .{})});
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",\"address\":");
        if (value.address) |address| {
            try writer.print("{f}", .{std.json.fmt(address, .{})});
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",\"session_id\":");
        try writer.print("{f}", .{std.json.fmt(value.session_id, .{})});
        try writer.writeAll(",\"session_kind\":");
        if (value.session_kind) |session_kind| {
            try writer.print("{f}", .{std.json.fmt(session_kind, .{})});
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll(",\"state\":");
        try writer.print("{f}", .{std.json.fmt(value.state, .{})});
        try writer.writeAll(",\"expires_at_ms\":");
        if (value.expires_at_ms) |expires_at_ms| {
            try writer.print("{d}", .{expires_at_ms});
        } else {
            try writer.writeAll("null");
        }
        try writer.print(",\"active_wallet_match\":{any}", .{value.active_wallet_match});
        try writer.writeAll(",\"registry_path\":");
        if (value.registry_path) |registry_path| {
            try writer.print("{f}", .{std.json.fmt(registry_path, .{})});
        } else {
            try writer.writeAll("null");
        }
        try writer.writeAll("}");
        return;
    }

    if (embedded_json) |value| {
        try writer.writeAll(value);
        return;
    }

    try writer.writeAll("null");
}

fn clearActiveWalletSelectorIfMatches(
    allocator: std.mem.Allocator,
    selector: []const u8,
    address: []const u8,
) !?[]u8 {
    const active_selector = try wallet_state.resolveActiveSelector(allocator);
    if (active_selector == null) return null;
    errdefer if (active_selector) |value| allocator.free(value);

    if (!sameWalletSelectorOrAddress(active_selector, selector, address)) {
        return active_selector;
    }
    allocator.free(active_selector.?);
    try wallet_state.writeDefaultWalletState(allocator, null);
    return null;
}

fn runWalletCreateOrImport(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
    action: []const u8,
    raw_key: []const u8,
) !void {
    const trimmed_raw_key = std.mem.trim(u8, raw_key, " \n\r\t");
    if (trimmed_raw_key.len == 0) return error.InvalidCli;

    const keystore_path = try client.keystore.resolveDefaultSuiKeystorePath(allocator) orelse return error.InvalidCli;
    defer allocator.free(keystore_path);

    const existing_contents = try readOptionalFileAtPathAlloc(allocator, keystore_path, 4 * 1024 * 1024);
    defer if (existing_contents) |value| allocator.free(value);

    const entry = try buildWalletStoredEntryJson(allocator, trimmed_raw_key, args.wallet_alias);
    defer allocator.free(entry.json);

    try validateWalletEntryUniqueness(
        allocator,
        existing_contents,
        args.wallet_alias,
        entry.address,
        entry.public_key,
    );

    const updated_contents = try appendEntryJsonToKeystoreContents(allocator, existing_contents, entry.json);
    defer allocator.free(updated_contents);
    try writeFileAtPath(keystore_path, updated_contents);

    const selector_source = args.wallet_alias orelse entry.address;
    var state_path: ?[]const u8 = null;
    if (args.wallet_activate) {
        try wallet_state.writeDefaultWalletState(allocator, selector_source);
        state_path = try wallet_state.resolveDefaultWalletStatePath(allocator);
    }

    var summary = OwnedWalletLifecycleSummary{
        .action = try allocator.dupe(u8, action),
        .selector = try allocator.dupe(u8, selector_source),
        .address = entry.address,
        .public_key = entry.public_key,
        .keystore_path = try allocator.dupe(u8, keystore_path),
        .wallet_state_path = state_path,
        .activated = args.wallet_activate,
    };
    defer summary.deinit(allocator);

    try formatWalletLifecycleSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn runWalletUse(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    const selector = args.account_selector orelse return error.InvalidCli;
    const address = if (std.mem.startsWith(u8, selector, "0x"))
        try allocator.dupe(u8, selector)
    else
        try client.keystore.resolveAddressBySelector(allocator, selector) orelse return error.InvalidCli;
    errdefer allocator.free(address);

    try wallet_state.writeDefaultWalletState(allocator, selector);
    const state_path = try wallet_state.resolveDefaultWalletStatePath(allocator);

    var summary = OwnedWalletLifecycleSummary{
        .action = try allocator.dupe(u8, "active_wallet_updated"),
        .selector = try allocator.dupe(u8, selector),
        .address = address,
        .wallet_state_path = state_path,
        .activated = true,
    };
    defer summary.deinit(allocator);

    try formatWalletLifecycleSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn resolvedWalletNetwork(network: ?[]const u8) []const u8 {
    return network orelse "sui:mainnet";
}

fn walletRegistryId(label: ?[]const u8, fallback: []const u8) []const u8 {
    if (label) |value| {
        if (value.len != 0) return value;
    }
    return fallback;
}

fn duplicateOptionalSlice(allocator: std.mem.Allocator, value: ?[]const u8) !?[]u8 {
    const slice = value orelse return null;
    return try allocator.dupe(u8, slice);
}

fn freeOwnedWalletAccountList(
    allocator: std.mem.Allocator,
    entries: *std.ArrayList(OwnedWalletAccountListEntry),
) void {
    for (entries.items) |*entry| entry.deinit(allocator);
    entries.deinit(allocator);
}

fn appendExternalWalletRegistryEntry(
    allocator: std.mem.Allocator,
    registry: *wallet_registry.OwnedWalletRegistry,
    entry: wallet_registry.OwnedExternalWalletEntry,
) !void {
    const old_entries = registry.external_wallets;
    const new_entries = try allocator.alloc(wallet_registry.OwnedExternalWalletEntry, old_entries.len + 1);
    for (old_entries, 0..) |old_entry, index| new_entries[index] = old_entry;
    new_entries[old_entries.len] = entry;
    allocator.free(old_entries);
    registry.external_wallets = new_entries;
}

fn appendPasskeyRegistryEntry(
    allocator: std.mem.Allocator,
    registry: *wallet_registry.OwnedWalletRegistry,
    entry: wallet_registry.OwnedPasskeyCredentialEntry,
) !void {
    const old_entries = registry.passkey_credentials;
    const new_entries = try allocator.alloc(wallet_registry.OwnedPasskeyCredentialEntry, old_entries.len + 1);
    for (old_entries, 0..) |old_entry, index| new_entries[index] = old_entry;
    new_entries[old_entries.len] = entry;
    allocator.free(old_entries);
    registry.passkey_credentials = new_entries;
}

fn appendWalletSessionRegistryEntry(
    allocator: std.mem.Allocator,
    registry: *wallet_session_registry.OwnedWalletSessionRegistry,
    entry: wallet_session_registry.OwnedWalletSessionEntry,
) !void {
    const old_entries = registry.entries;
    const new_entries = try allocator.alloc(wallet_session_registry.OwnedWalletSessionEntry, old_entries.len + 1);
    for (old_entries, 0..) |old_entry, index| new_entries[index] = old_entry;
    new_entries[old_entries.len] = entry;
    allocator.free(old_entries);
    registry.entries = new_entries;
}

fn replaceExternalWalletRegistryEntryAt(
    allocator: std.mem.Allocator,
    registry: *wallet_registry.OwnedWalletRegistry,
    index: usize,
    entry: wallet_registry.OwnedExternalWalletEntry,
) void {
    registry.external_wallets[index].deinit(allocator);
    registry.external_wallets[index] = entry;
}

fn replacePasskeyRegistryEntryAt(
    allocator: std.mem.Allocator,
    registry: *wallet_registry.OwnedWalletRegistry,
    index: usize,
    entry: wallet_registry.OwnedPasskeyCredentialEntry,
) void {
    registry.passkey_credentials[index].deinit(allocator);
    registry.passkey_credentials[index] = entry;
}

fn replaceWalletSessionRegistryEntryAt(
    allocator: std.mem.Allocator,
    registry: *wallet_session_registry.OwnedWalletSessionRegistry,
    index: usize,
    entry: wallet_session_registry.OwnedWalletSessionEntry,
) void {
    registry.entries[index].deinit(allocator);
    registry.entries[index] = entry;
}

fn buildWalletAccountsSummary(
    allocator: std.mem.Allocator,
    passkey_only: bool,
) !OwnedWalletAccountsSummary {
    const active_selector = try wallet_state.resolveActiveSelector(allocator);
    errdefer if (active_selector) |value| allocator.free(value);

    const registry_path = try wallet_registry.resolveDefaultWalletRegistryPath(allocator);
    errdefer if (registry_path) |value| allocator.free(value);
    var registry = try wallet_registry.loadDefaultWalletRegistry(allocator);
    defer registry.deinit(allocator);

    const keystore_path = if (passkey_only) null else try client.keystore.resolveDefaultSuiKeystorePath(allocator);
    errdefer if (keystore_path) |value| allocator.free(value);

    var entries = std.ArrayList(OwnedWalletAccountListEntry){};
    errdefer freeOwnedWalletAccountList(allocator, &entries);

    if (!passkey_only) {
        if (keystore_path) |path| {
            const contents = try readOptionalFileAtPathAlloc(allocator, path, 4 * 1024 * 1024);
            defer if (contents) |value| allocator.free(value);
            if (contents) |keystore_contents| {
                var account_entries = try client.keystore.listAccountEntriesFromContents(allocator, keystore_contents);
                defer account_entries.deinit(allocator);

                for (account_entries.accounts) |entry| {
                    const address_value = entry.address orelse entry.sui_address orelse continue;
                    const public_selector = publicSelectorFromEntry(entry, null);
                    const selector_owned = if (public_selector) |value|
                        try allocator.dupe(u8, value)
                    else
                        try std.fmt.allocPrint(allocator, "{d}", .{entry.index});
                    errdefer allocator.free(selector_owned);

                    const address_owned = try allocator.dupe(u8, address_value);
                    errdefer allocator.free(address_owned);
                    const public_key_owned = try duplicateOptionalSlice(allocator, entry.public_key);
                    errdefer if (public_key_owned) |value| allocator.free(value);

                    const key = try client.keystore.parseKeyBySelector(allocator, keystore_contents, selector_owned);
                    const can_sign_locally = if (key) |value| blk: {
                        allocator.free(value);
                        break :blk true;
                    } else false;

                    try entries.append(allocator, .{
                        .source_kind = try allocator.dupe(u8, "keystore"),
                        .mode = try allocator.dupe(u8, "local_keystore"),
                        .selector = selector_owned,
                        .label = try duplicateOptionalSlice(allocator, entry.alias orelse entry.name),
                        .address = address_owned,
                        .public_key = public_key_owned,
                        .network = null,
                        .state = try allocator.dupe(u8, "available"),
                        .active_match = sameWalletSelectorOrAddress(active_selector, selector_owned, address_owned),
                        .can_sign_locally = can_sign_locally,
                    });
                }
            }
        }
    }

    for (registry.passkey_credentials) |entry| {
        try entries.append(allocator, .{
            .source_kind = try allocator.dupe(u8, "wallet_registry"),
            .mode = try allocator.dupe(u8, "embedded_passkey"),
            .selector = try allocator.dupe(u8, entry.selector),
            .label = try duplicateOptionalSlice(allocator, entry.label),
            .address = try allocator.dupe(u8, entry.address),
            .public_key = try allocator.dupe(u8, entry.public_key),
            .network = try duplicateOptionalSlice(allocator, entry.network),
            .state = try allocator.dupe(u8, entry.state),
            .active_match = sameWalletSelectorOrAddress(active_selector, entry.selector, entry.address),
            .can_sign_locally = false,
        });
    }

    if (!passkey_only) {
        for (registry.external_wallets) |entry| {
            try entries.append(allocator, .{
                .source_kind = try allocator.dupe(u8, "wallet_registry"),
                .mode = try allocator.dupe(u8, "external_wallet"),
                .selector = try allocator.dupe(u8, entry.selector),
                .label = try duplicateOptionalSlice(allocator, entry.label),
                .address = try allocator.dupe(u8, entry.address),
                .public_key = null,
                .network = try duplicateOptionalSlice(allocator, entry.network),
                .state = try allocator.dupe(u8, entry.state),
                .active_match = sameWalletSelectorOrAddress(active_selector, entry.selector, entry.address),
                .can_sign_locally = false,
            });
        }
    }

    return .{
        .artifact_kind = if (passkey_only) "wallet_passkey_list" else "wallet_accounts",
        .active_selector = active_selector,
        .registry_path = registry_path,
        .keystore_path = keystore_path,
        .entries = try entries.toOwnedSlice(allocator),
    };
}

fn runWalletAccounts(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
    passkey_only: bool,
) !void {
    var summary = try buildWalletAccountsSummary(allocator, passkey_only);
    defer summary.deinit(allocator);
    try formatWalletAccountsSummary(writer, &summary, args.pretty);
}

fn runWalletConnect(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    const address = args.account_selector orelse return error.InvalidCli;
    const label = args.wallet_alias;

    const registry_path = try wallet_registry.resolveDefaultWalletRegistryPath(allocator) orelse return error.InvalidCli;
    defer allocator.free(registry_path);

    var registry = try wallet_registry.loadDefaultWalletRegistry(allocator);
    defer registry.deinit(allocator);

    const selector_id = walletRegistryId(label, address);
    const selector = try wallet_registry.externalSelectorForId(allocator, selector_id);
    defer allocator.free(selector);

    const now_ms = std.time.milliTimestamp();
    const entry = wallet_registry.OwnedExternalWalletEntry{
        .selector = try allocator.dupe(u8, selector),
        .label = try duplicateOptionalSlice(allocator, label),
        .address = try allocator.dupe(u8, address),
        .network = try allocator.dupe(u8, resolvedWalletNetwork(args.wallet_network)),
        .capabilities_json = try duplicateOptionalSlice(allocator, args.wallet_capabilities_json),
        .state = try allocator.dupe(u8, "connected"),
        .connected_at_ms = now_ms,
        .updated_at_ms = now_ms,
    };

    var existing_index = findExternalWalletIndexAnyState(&registry, address);
    if (existing_index == null and label != null) {
        existing_index = findExternalWalletIndexAnyState(&registry, label.?);
    }

    if (existing_index) |index| {
        replaceExternalWalletRegistryEntryAt(allocator, &registry, index, entry);
    } else {
        try appendExternalWalletRegistryEntry(allocator, &registry, entry);
    }

    try wallet_registry.writeDefaultWalletRegistry(allocator, &registry);

    var wallet_state_path: ?[]const u8 = null;
    if (args.wallet_activate) {
        try wallet_state.writeDefaultWalletState(allocator, selector);
        wallet_state_path = try wallet_state.resolveDefaultWalletStatePath(allocator);
    }

    var summary = OwnedWalletRegistryLifecycleSummary{
        .action = try allocator.dupe(u8, "external_wallet_connected"),
        .source_kind = try allocator.dupe(u8, "external_wallet"),
        .selector = try allocator.dupe(u8, selector),
        .address = try allocator.dupe(u8, address),
        .label = try duplicateOptionalSlice(allocator, label),
        .network = try allocator.dupe(u8, resolvedWalletNetwork(args.wallet_network)),
        .state = try allocator.dupe(u8, "connected"),
        .registry_path = try allocator.dupe(u8, registry_path),
        .wallet_state_path = wallet_state_path,
        .activated = args.wallet_activate,
    };
    defer summary.deinit(allocator);

    try formatWalletRegistryLifecycleSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn runWalletDisconnect(
    allocator: std.mem.Allocator,
