fn defaultWalletSessionKindForResolved(
    source_kind: []const u8,
    selector: ?[]const u8,
) []const u8 {
    if (selector) |value| {
        if (std.mem.startsWith(u8, value, "passkey:")) return "passkey";
        if (std.mem.startsWith(u8, value, "external:")) return "external_wallet";
    }
    if (std.mem.eql(u8, source_kind, "embedded_passkey")) return "passkey";
    if (std.mem.eql(u8, source_kind, "external_wallet")) return "external_wallet";
    return "local_signer";
}

fn runWalletSessionCreate(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    const session_id = args.wallet_session_id orelse return error.InvalidCli;

    var resolved = try resolveWalletEntrySummary(allocator, args);
    defer resolved.deinit(allocator);

    const registry_path = try wallet_session_registry.resolveDefaultWalletSessionRegistryPath(allocator) orelse return error.InvalidCli;
    defer allocator.free(registry_path);

    var registry = try wallet_session_registry.loadDefaultWalletSessionRegistry(allocator);
    defer registry.deinit(allocator);

    const selector_id = walletRegistryId(args.wallet_alias, session_id);
    const selector = try wallet_session_registry.sessionSelectorForId(allocator, selector_id);
    defer allocator.free(selector);

    const policy_json = try buildMergedWalletPolicyJson(allocator, args);
    defer if (policy_json) |value| allocator.free(value);

    const now_ms = std.time.milliTimestamp();
    const entry = wallet_session_registry.OwnedWalletSessionEntry{
        .selector = try allocator.dupe(u8, selector),
        .label = try duplicateOptionalSlice(allocator, args.wallet_alias),
        .wallet_selector = if (resolved.selector) |value| try allocator.dupe(u8, value) else null,
        .address = if (resolved.address) |value| try allocator.dupe(u8, value) else null,
        .session_id = try allocator.dupe(u8, session_id),
        .session_kind = try allocator.dupe(u8, args.wallet_session_kind orelse defaultWalletSessionKindForResolved(resolved.source_kind, resolved.selector)),
        .state = try allocator.dupe(u8, "active"),
        .policy_json = if (policy_json) |value| try allocator.dupe(u8, value) else null,
        .created_at_ms = now_ms,
        .updated_at_ms = now_ms,
        .expires_at_ms = if (args.wallet_session_expires_at_ms) |value| @as(i64, @intCast(value)) else null,
    };

    var existing_index = findWalletSessionIndexAnyState(&registry, session_id);
    if (existing_index == null and args.wallet_alias != null) {
        existing_index = findWalletSessionIndexAnyState(&registry, args.wallet_alias.?);
    }
    if (existing_index == null) {
        existing_index = findWalletSessionIndexAnyState(&registry, selector);
    }

    if (existing_index) |index| {
        replaceWalletSessionRegistryEntryAt(allocator, &registry, index, entry);
    } else {
        try appendWalletSessionRegistryEntry(allocator, &registry, entry);
    }

    try wallet_session_registry.writeDefaultWalletSessionRegistry(allocator, &registry);

    var summary = OwnedWalletSessionLifecycleSummary{
        .action = try allocator.dupe(u8, "session_created"),
        .selector = try allocator.dupe(u8, selector),
        .label = try duplicateOptionalSlice(allocator, args.wallet_alias),
        .wallet_selector = if (resolved.selector) |value| try allocator.dupe(u8, value) else null,
        .address = if (resolved.address) |value| try allocator.dupe(u8, value) else null,
        .session_id = try allocator.dupe(u8, session_id),
        .session_kind = try allocator.dupe(u8, args.wallet_session_kind orelse defaultWalletSessionKindForResolved(resolved.source_kind, resolved.selector)),
        .state = try allocator.dupe(u8, "active"),
        .policy_json = if (policy_json) |value| try allocator.dupe(u8, value) else null,
        .created_at_ms = now_ms,
        .updated_at_ms = now_ms,
        .expires_at_ms = if (args.wallet_session_expires_at_ms) |value| @as(i64, @intCast(value)) else null,
        .active_selector = if (resolved.active_selector) |value| try allocator.dupe(u8, value) else null,
        .active_wallet_match = sessionEntryMatchesActiveWalletSelector(resolved.active_selector, &registry.entries[existing_index orelse (registry.entries.len - 1)]),
        .registry_path = try allocator.dupe(u8, registry_path),
    };
    defer summary.deinit(allocator);

    try formatWalletSessionLifecycleSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn buildWalletSessionListSummary(
    allocator: std.mem.Allocator,
) !OwnedWalletSessionListSummary {
    const active_selector = try wallet_state.resolveActiveSelector(allocator);
    errdefer if (active_selector) |value| allocator.free(value);

    const registry_path = try wallet_session_registry.resolveDefaultWalletSessionRegistryPath(allocator);
    errdefer if (registry_path) |value| allocator.free(value);

    var registry = try wallet_session_registry.loadDefaultWalletSessionRegistry(allocator);
    defer registry.deinit(allocator);

    const entries = try allocator.alloc(OwnedWalletSessionListEntry, registry.entries.len);
    errdefer allocator.free(entries);

    for (registry.entries, 0..) |entry, index| {
        entries[index] = .{
            .selector = try allocator.dupe(u8, entry.selector),
            .label = try duplicateOptionalSlice(allocator, entry.label),
            .wallet_selector = try duplicateOptionalSlice(allocator, entry.wallet_selector),
            .address = try duplicateOptionalSlice(allocator, entry.address),
            .session_id = try allocator.dupe(u8, entry.session_id),
            .session_kind = try duplicateOptionalSlice(allocator, entry.session_kind),
            .state = try allocator.dupe(u8, entry.state),
            .policy_json = try duplicateOptionalSlice(allocator, entry.policy_json),
            .created_at_ms = entry.created_at_ms,
            .updated_at_ms = entry.updated_at_ms,
            .expires_at_ms = entry.expires_at_ms,
            .active_wallet_match = sessionEntryMatchesActiveWalletSelector(active_selector, &entry),
        };
    }

    return .{
        .active_selector = active_selector,
        .registry_path = registry_path,
        .entries = entries,
    };
}

fn runWalletSessionList(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    var summary = try buildWalletSessionListSummary(allocator);
    defer summary.deinit(allocator);
    try formatWalletSessionListSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn runWalletSessionRevoke(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    const selector_or_address = args.account_selector orelse return error.InvalidCli;

    const registry_path = try wallet_session_registry.resolveDefaultWalletSessionRegistryPath(allocator) orelse return error.InvalidCli;
    defer allocator.free(registry_path);

    var registry = try wallet_session_registry.loadDefaultWalletSessionRegistry(allocator);
    defer registry.deinit(allocator);

    const index = findWalletSessionIndexAnyState(&registry, selector_or_address) orelse return error.InvalidCli;
    const entry = &registry.entries[index];

    allocator.free(entry.state);
    entry.state = try allocator.dupe(u8, "revoked");
    entry.updated_at_ms = std.time.milliTimestamp();

    try wallet_session_registry.writeDefaultWalletSessionRegistry(allocator, &registry);

    const active_selector = try wallet_state.resolveActiveSelector(allocator);

    var summary = OwnedWalletSessionLifecycleSummary{
        .action = try allocator.dupe(u8, "session_revoked"),
        .selector = try allocator.dupe(u8, entry.selector),
        .label = try duplicateOptionalSlice(allocator, entry.label),
        .wallet_selector = try duplicateOptionalSlice(allocator, entry.wallet_selector),
        .address = try duplicateOptionalSlice(allocator, entry.address),
        .session_id = try allocator.dupe(u8, entry.session_id),
        .session_kind = try duplicateOptionalSlice(allocator, entry.session_kind),
        .state = try allocator.dupe(u8, entry.state),
        .policy_json = try duplicateOptionalSlice(allocator, entry.policy_json),
        .created_at_ms = entry.created_at_ms,
        .updated_at_ms = entry.updated_at_ms,
        .expires_at_ms = entry.expires_at_ms,
        .active_selector = active_selector,
        .active_wallet_match = sessionEntryMatchesActiveWalletSelector(active_selector, entry),
        .registry_path = try allocator.dupe(u8, registry_path),
    };
    defer summary.deinit(allocator);

    try formatWalletSessionLifecycleSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn runWalletPolicyInspect(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    const inline_policy_present = args.intent_policy_json != null or anyExtraIntentPolicyFields(args);

    if (args.account_selector) |selector_or_address| {
        const registry_path = try wallet_session_registry.resolveDefaultWalletSessionRegistryPath(allocator) orelse return error.InvalidCli;
        defer allocator.free(registry_path);

        var registry = try wallet_session_registry.loadDefaultWalletSessionRegistry(allocator);
        defer registry.deinit(allocator);

        const index = findWalletSessionIndexAnyState(&registry, selector_or_address) orelse return error.InvalidCli;
        const entry = &registry.entries[index];
        const active_selector = try wallet_state.resolveActiveSelector(allocator);
        const policy_json = try buildMergedWalletPolicyJsonWithBase(allocator, entry.policy_json, args);
        defer if (policy_json) |value| allocator.free(value);

        var summary = OwnedWalletPolicyInspectSummary{
            .source_kind = try allocator.dupe(u8, if (inline_policy_present) "session_registry_plus_inline" else "session_registry"),
            .selector = try allocator.dupe(u8, entry.selector),
            .wallet_selector = try duplicateOptionalSlice(allocator, entry.wallet_selector),
            .address = try duplicateOptionalSlice(allocator, entry.address),
            .session_id = try allocator.dupe(u8, entry.session_id),
            .session_kind = try duplicateOptionalSlice(allocator, entry.session_kind),
            .state = try allocator.dupe(u8, entry.state),
            .active_selector = active_selector,
            .active_wallet_match = sessionEntryMatchesActiveWalletSelector(active_selector, entry),
            .registry_path = try allocator.dupe(u8, registry_path),
            .policy_json = try duplicateOptionalSlice(allocator, policy_json),
        };
        defer summary.deinit(allocator);

        try formatWalletPolicyInspectSummary(writer, &summary, args.wallet_json, args.pretty);
        return;
    }

    const active_selector = try wallet_state.resolveActiveSelector(allocator);
    const policy_json = try buildMergedWalletPolicyJson(allocator, args);
    defer if (policy_json) |value| allocator.free(value);

    var summary = OwnedWalletPolicyInspectSummary{
        .source_kind = try allocator.dupe(u8, "inline"),
        .active_selector = active_selector,
        .policy_json = try duplicateOptionalSlice(allocator, policy_json),
    };
    defer summary.deinit(allocator);

    try formatWalletPolicyInspectSummary(writer, &summary, args.wallet_json, args.pretty);
}

fn sameWalletSelectorOrAddress(
    active_selector: ?[]const u8,
    selector: ?[]const u8,
    address: ?[]const u8,
) bool {
    const active = active_selector orelse return false;
    if (selector) |value| {
        if (std.mem.eql(u8, active, value)) return true;
    }
    if (address) |value| {
        if (std.mem.eql(u8, active, value)) return true;
    }
    return false;
}

fn publicSelectorFromEntry(
    entry: client.keystore.OwnedAccountEntry,
    fallback_selector: ?[]u8,
) ?[]const u8 {
    if (entry.alias) |value| return value;
    if (entry.name) |value| return value;
    if (entry.address orelse entry.sui_address) |value| return value;
    if (entry.public_key) |value| return value;
    if (fallback_selector) |value| {
        if (std.mem.startsWith(u8, value, "0x")) return value;
    }
    return null;
}

fn resolveWalletEntrySummary(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) !OwnedResolvedWalletEntrySummary {
    const registry_path = try wallet_registry.resolveDefaultWalletRegistryPath(allocator);
    errdefer if (registry_path) |value| allocator.free(value);
    var registry = try wallet_registry.loadDefaultWalletRegistry(allocator);
    defer registry.deinit(allocator);

    const keystore_path = try client.keystore.resolveDefaultSuiKeystorePath(allocator);
    errdefer if (keystore_path) |value| allocator.free(value);
    const keystore_contents = if (keystore_path) |path|
        try readOptionalFileAtPathAlloc(allocator, path, 4 * 1024 * 1024)
    else
        null;
    defer if (keystore_contents) |value| allocator.free(value);

    const wallet_state_path = try wallet_state.resolveDefaultWalletStatePath(allocator);
    errdefer if (wallet_state_path) |value| allocator.free(value);
    const active_selector = try wallet_state.resolveActiveSelector(allocator);
    errdefer if (active_selector) |value| allocator.free(value);

    var entry: ?client.keystore.OwnedAccountEntry = null;
    var source_kind: []const u8 = undefined;
    var fallback_selector: ?[]u8 = null;
    errdefer if (fallback_selector) |value| allocator.free(value);
    var fallback_address: ?[]u8 = null;
    errdefer if (fallback_address) |value| allocator.free(value);
    var can_sign_locally = false;
    var resolved_network: ?[]u8 = null;
    errdefer if (resolved_network) |value| allocator.free(value);
    var resolved_state: ?[]u8 = null;
    errdefer if (resolved_state) |value| allocator.free(value);

    const setFallbackSelector = struct {
        fn call(allocator_inner: std.mem.Allocator, target: *?[]u8, value: []const u8) !void {
            if (target.*) |existing| allocator_inner.free(existing);
            target.* = try allocator_inner.dupe(u8, value);
        }
    }.call;

    const setFallbackAddress = struct {
        fn call(allocator_inner: std.mem.Allocator, target: *?[]u8, value: []const u8) !void {
            if (target.*) |existing| allocator_inner.free(existing);
            target.* = try allocator_inner.dupe(u8, value);
        }
    }.call;

    if (args.account_selector) |selector| {
        try setFallbackSelector(allocator, &fallback_selector, selector);
        if (std.mem.startsWith(u8, selector, "0x")) {
            source_kind = "explicit_address";
            if (keystore_contents) |contents| {
                entry = try client.keystore.getAccountEntryFromContents(allocator, contents, selector);
                const local_key = try client.keystore.parseKeyBySelector(allocator, contents, selector);
                if (local_key) |value| {
                    can_sign_locally = true;
                    allocator.free(value);
                }
            }
            if (entry == null) {
                if (findActivePasskeyIndex(&registry, selector)) |index| {
                    const passkey = registry.passkey_credentials[index];
                    source_kind = "embedded_passkey";
                    try setFallbackSelector(allocator, &fallback_selector, passkey.selector);
                    try setFallbackAddress(allocator, &fallback_address, passkey.address);
                    resolved_network = try duplicateOptionalOwned(allocator, passkey.network);
                    resolved_state = try allocator.dupe(u8, passkey.state);
                } else if (findConnectedExternalWalletIndex(&registry, selector)) |index| {
                    const external = registry.external_wallets[index];
                    source_kind = "external_wallet";
                    try setFallbackSelector(allocator, &fallback_selector, external.selector);
                    try setFallbackAddress(allocator, &fallback_address, external.address);
                    resolved_network = try duplicateOptionalOwned(allocator, external.network);
                    resolved_state = try allocator.dupe(u8, external.state);
                } else {
                    try setFallbackAddress(allocator, &fallback_address, selector);
                }
            }
        } else {
            if (findActivePasskeyIndex(&registry, selector)) |index| {
                const passkey = registry.passkey_credentials[index];
                source_kind = "embedded_passkey";
                try setFallbackSelector(allocator, &fallback_selector, passkey.selector);
                try setFallbackAddress(allocator, &fallback_address, passkey.address);
                resolved_network = try duplicateOptionalOwned(allocator, passkey.network);
                resolved_state = try allocator.dupe(u8, passkey.state);
            } else if (findConnectedExternalWalletIndex(&registry, selector)) |index| {
                const external = registry.external_wallets[index];
                source_kind = "external_wallet";
                try setFallbackSelector(allocator, &fallback_selector, external.selector);
                try setFallbackAddress(allocator, &fallback_address, external.address);
                resolved_network = try duplicateOptionalOwned(allocator, external.network);
                resolved_state = try allocator.dupe(u8, external.state);
            } else {
                source_kind = "explicit_selector";
                const contents = keystore_contents orelse return error.InvalidCli;
                entry = try client.keystore.getAccountEntryFromContents(allocator, contents, selector) orelse return error.InvalidCli;
                const local_key = try client.keystore.parseKeyBySelector(allocator, contents, selector);
                if (local_key) |value| {
                    can_sign_locally = true;
                    allocator.free(value);
                }
            }
        }
    } else if (active_selector) |selector| {
        try setFallbackSelector(allocator, &fallback_selector, selector);
        if (findActivePasskeyIndex(&registry, selector)) |index| {
            const passkey = registry.passkey_credentials[index];
            source_kind = "active_wallet";
            try setFallbackSelector(allocator, &fallback_selector, passkey.selector);
            try setFallbackAddress(allocator, &fallback_address, passkey.address);
            resolved_network = try duplicateOptionalOwned(allocator, passkey.network);
            resolved_state = try allocator.dupe(u8, passkey.state);
        } else if (findConnectedExternalWalletIndex(&registry, selector)) |index| {
            const external = registry.external_wallets[index];
            source_kind = "active_wallet";
            try setFallbackSelector(allocator, &fallback_selector, external.selector);
            try setFallbackAddress(allocator, &fallback_address, external.address);
            resolved_network = try duplicateOptionalOwned(allocator, external.network);
            resolved_state = try allocator.dupe(u8, external.state);
        } else if (std.mem.startsWith(u8, selector, "0x")) {
            source_kind = "active_wallet";
            if (keystore_contents) |contents| {
                entry = try client.keystore.getAccountEntryFromContents(allocator, contents, selector);
                const local_key = try client.keystore.parseKeyBySelector(allocator, contents, selector);
                if (local_key) |value| {
                    can_sign_locally = true;
                    allocator.free(value);
                }
            }
            if (entry == null) {
                try setFallbackAddress(allocator, &fallback_address, selector);
            }
        } else {
            source_kind = "active_wallet";
            const contents = keystore_contents orelse return error.InvalidCli;
            entry = try client.keystore.getAccountEntryFromContents(allocator, contents, selector) orelse return error.InvalidCli;
            const local_key = try client.keystore.parseKeyBySelector(allocator, contents, selector);
            if (local_key) |value| {
                can_sign_locally = true;
                allocator.free(value);
            }
        }
    } else {
        source_kind = "default_keystore_first";
        const contents = keystore_contents orelse return error.InvalidCli;
        entry = try client.keystore.getFirstAccountEntryFromContents(allocator, contents) orelse return error.InvalidCli;
        const first_key = try client.keystore.parseFirstKey(allocator, contents);
        if (first_key) |value| {
            can_sign_locally = true;
            allocator.free(value);
        }
        if (entry) |resolved_entry| {
            fallback_selector = try duplicateOptionalSlice(allocator, resolved_entry.selector);
        }
    }
    defer if (entry) |*value| value.deinit(allocator);

    const selector = blk: {
        if (entry) |value| {
            if (publicSelectorFromEntry(value, fallback_selector)) |entry_selector| {
                if (fallback_selector) |owned_fallback| {
                    if (entry_selector.ptr == owned_fallback.ptr and entry_selector.len == owned_fallback.len) {
                        fallback_selector = null;
                        break :blk owned_fallback;
                    }
                    allocator.free(owned_fallback);
                    fallback_selector = null;
                }
                break :blk try allocator.dupe(u8, entry_selector);
            }
        }
        const owned_fallback = fallback_selector;
        fallback_selector = null;
        break :blk owned_fallback;
    };

    const alias = if (entry) |value| try duplicateOptionalSlice(allocator, value.alias) else null;
    const name = if (entry) |value| try duplicateOptionalSlice(allocator, value.name) else null;
    const address = blk: {
        if (entry) |value| {
            if (value.address orelse value.sui_address) |entry_address| {
                break :blk try allocator.dupe(u8, entry_address);
            }
        }
        break :blk fallback_address;
    };
    fallback_address = null;
    const public_key = if (entry) |value| try duplicateOptionalSlice(allocator, value.public_key) else null;
    const source_kind_owned = try allocator.dupe(u8, source_kind);
    const active_selector_owned = active_selector;

    return .{
        .source_kind = source_kind_owned,
        .selector = selector,
        .alias = alias,
        .name = name,
        .address = address,
        .public_key = public_key,
        .network = resolved_network,
        .state = resolved_state,
        .active_selector = active_selector_owned,
        .active_match = sameWalletSelectorOrAddress(active_selector, selector, address),
        .can_sign_locally = can_sign_locally,
        .registry_path = registry_path,
        .keystore_path = keystore_path,
        .wallet_state_path = wallet_state_path,
    };
}

fn formatWalletPublicExportSummary(
    writer: anytype,
    summary: *const OwnedWalletPublicExportSummary,
    json_output: bool,
    pretty: bool,
) !void {
    if (json_output or pretty) {
        try printStructuredJson(writer, summary.*, pretty);
        return;
    }

    try writer.writeAll("wallet public export\n");
    try writer.print("source: {s}\n", .{summary.source_kind});
    if (summary.selector) |value| try writer.print("selector: {s}\n", .{value});
    if (summary.alias) |value| try writer.print("alias: {s}\n", .{value});
    if (summary.name) |value| try writer.print("name: {s}\n", .{value});
    if (summary.address) |value| try writer.print("address: {s}\n", .{value});
    if (summary.public_key) |value| try writer.print("public_key: {s}\n", .{value});
    if (summary.network) |value| try writer.print("network: {s}\n", .{value});
    if (summary.state) |value| try writer.print("state: {s}\n", .{value});
    if (summary.active_selector) |value| try writer.print("active_selector: {s}\n", .{value});
    try writer.print("active_match: {any}\n", .{summary.active_match});
}

fn formatWalletSignerInspectSummary(
    writer: anytype,
    summary: *const OwnedWalletSignerInspectSummary,
    json_output: bool,
    pretty: bool,
) !void {
    if (json_output or pretty) {
        try printStructuredJson(writer, summary.*, pretty);
        return;
    }

    try writer.writeAll("wallet signer inspect\n");
    try writer.print("source: {s}\n", .{summary.source_kind});
    if (summary.selector) |value| try writer.print("selector: {s}\n", .{value});
    if (summary.alias) |value| try writer.print("alias: {s}\n", .{value});
    if (summary.name) |value| try writer.print("name: {s}\n", .{value});
    if (summary.address) |value| try writer.print("address: {s}\n", .{value});
    if (summary.public_key) |value| try writer.print("public_key: {s}\n", .{value});
    if (summary.network) |value| try writer.print("network: {s}\n", .{value});
    if (summary.state) |value| try writer.print("state: {s}\n", .{value});
    if (summary.active_selector) |value| try writer.print("active_selector: {s}\n", .{value});
    try writer.print("active_match: {any}\n", .{summary.active_match});
    try writer.print("can_sign_locally: {any}\n", .{summary.can_sign_locally});
    try writer.print("sender_resolution_kind: {s}\n", .{summary.sender_resolution_kind});
    if (summary.registry_path) |value| try writer.print("wallet_registry: {s}\n", .{value});
    if (summary.keystore_path) |value| try writer.print("keystore: {s}\n", .{value});
    if (summary.wallet_state_path) |value| try writer.print("wallet_state: {s}\n", .{value});
}

const WalletOwnerResolution = struct {
    owner: []const u8,
    owned: ?[]const u8,
};

fn resolveWalletOwnerFromSelector(
    allocator: std.mem.Allocator,
    selector: ?[]const u8,
) !WalletOwnerResolution {
    var registry = try wallet_registry.loadDefaultWalletRegistry(allocator);
    defer registry.deinit(allocator);

    if (selector) |value| {
        if (std.mem.startsWith(u8, value, "0x")) {
            if (findActivePasskeyIndex(&registry, value)) |index| {
                const resolved = try allocator.dupe(u8, registry.passkey_credentials[index].address);
                return .{ .owner = resolved, .owned = resolved };
            }
            if (findConnectedExternalWalletIndex(&registry, value)) |index| {
                const resolved = try allocator.dupe(u8, registry.external_wallets[index].address);
                return .{ .owner = resolved, .owned = resolved };
            }
            return .{
                .owner = value,
                .owned = null,
            };
        }

        if (findActivePasskeyIndex(&registry, value)) |index| {
            const resolved = try allocator.dupe(u8, registry.passkey_credentials[index].address);
            return .{ .owner = resolved, .owned = resolved };
        }
        if (findConnectedExternalWalletIndex(&registry, value)) |index| {
            const resolved = try allocator.dupe(u8, registry.external_wallets[index].address);
            return .{ .owner = resolved, .owned = resolved };
        }

        const resolved_explicit = try client.keystore.resolveAddressBySelector(allocator, value) orelse return error.InvalidCli;
        return .{
            .owner = resolved_explicit,
            .owned = resolved_explicit,
        };
    }

    if (try wallet_state.resolveActiveSelector(allocator)) |active_selector| {
        if (findActivePasskeyIndex(&registry, active_selector)) |index| {
            allocator.free(active_selector);
            const resolved = try allocator.dupe(u8, registry.passkey_credentials[index].address);
            return .{ .owner = resolved, .owned = resolved };
        }
        if (findConnectedExternalWalletIndex(&registry, active_selector)) |index| {
            allocator.free(active_selector);
            const resolved = try allocator.dupe(u8, registry.external_wallets[index].address);
            return .{ .owner = resolved, .owned = resolved };
        }
        if (std.mem.startsWith(u8, active_selector, "0x")) {
            return .{
                .owner = active_selector,
                .owned = active_selector,
            };
        }
        defer allocator.free(active_selector);
        const resolved_active = try client.keystore.resolveAddressBySelector(allocator, active_selector) orelse return error.InvalidCli;
        return .{ .owner = resolved_active, .owned = resolved_active };
    }

    const resolved_default = try client.keystore.resolveFirstAddressFromDefaultKeystore(allocator) orelse return error.InvalidCli;
    return .{ .owner = resolved_default, .owned = resolved_default };
}

fn resolveWalletOwner(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) !WalletOwnerResolution {
    return try resolveWalletOwnerFromSelector(allocator, args.account_selector);
}

fn buildWalletFundCommandsJson(
    allocator: std.mem.Allocator,
    amount: u64,
    destination: []const u8,
) ![]u8 {
    var builder = tx_builder.CommandBuilder.init(allocator);
    defer builder.deinit();

    const amounts_json = try std.fmt.allocPrint(allocator, "[{d}]", .{amount});
    defer allocator.free(amounts_json);
    const destination_json = try std.fmt.allocPrint(allocator, "{f}", .{std.json.fmt(destination, .{})});
    defer allocator.free(destination_json);

    try builder.appendSplitCoins(.{
        .coin_json = "\"GasCoin\"",
        .amounts_json = amounts_json,
    });
    try builder.appendTransferObjects(.{
        .objects_json = "[{\"NestedResult\":[0,0]}]",
        .address_json = destination_json,
    });
    return try builder.finish();
}

fn runWalletFund(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    writer: anytype,
    programmatic_provider: ?client.tx_request_builder.AccountProvider,
) anyerror!void {
    const amount = args.wallet_fund_amount orelse return error.InvalidCli;

    const destination = try resolveWalletOwnerFromSelector(allocator, args.account_selector);
    defer if (destination.owned) |value| allocator.free(value);

    var source_lookup_args = args.*;
    source_lookup_args.account_selector = args.tx_build_sender;
    var source_summary = try resolveWalletEntrySummary(allocator, &source_lookup_args);
    defer source_summary.deinit(allocator);
    const source_owner = source_summary.address orelse return error.InvalidCli;

    const commands_json = try buildWalletFundCommandsJson(allocator, amount, destination.owner);
    defer allocator.free(commands_json);

    var derived_args = cli.ParsedArgs{
        .command = if (args.wallet_fund_emit_request)
            .request_build
        else if (args.wallet_fund_dry_run)
            .request_dry_run
        else
            .request_send,
        .has_command = true,
        .pretty = args.pretty,
        .tx_build_gas_budget = args.tx_build_gas_budget,
        .tx_build_gas_price = args.tx_build_gas_price,
        .tx_build_auto_gas_payment = true,
        .tx_build_auto_gas_budget = args.tx_build_gas_budget == null,
        .tx_build_gas_payment_min_balance = args.tx_build_gas_payment_min_balance orelse amount,
        .tx_send_wait = args.tx_send_wait,
        .tx_send_summarize = args.tx_send_summarize,
        .tx_send_observe = args.tx_send_observe,
        .confirm_timeout_ms = args.confirm_timeout_ms,
        .confirm_poll_ms = args.confirm_poll_ms,
    };
    defer derived_args.deinit(allocator);

    derived_args.owned_tx_build_commands = try allocator.dupe(u8, commands_json);
    derived_args.tx_build_commands = derived_args.owned_tx_build_commands;
    derived_args.owned_tx_build_sender = try allocator.dupe(u8, source_owner);
    derived_args.tx_build_sender = derived_args.owned_tx_build_sender;

    if (args.tx_session_response) |raw| {
        derived_args.owned_tx_session_response = try allocator.dupe(u8, raw);
        derived_args.tx_session_response = derived_args.owned_tx_session_response;
    }
    if (args.tx_provider_config) |raw| {
        derived_args.owned_tx_provider_config = try allocator.dupe(u8, raw);
        derived_args.tx_provider_config = derived_args.owned_tx_provider_config;
    }

    if (!args.wallet_fund_emit_request and !args.wallet_fund_dry_run and programmatic_provider == null and args.tx_provider_config == null) {
        if (!source_summary.can_sign_locally) return error.InvalidCli;
        derived_args.from_keystore = true;
    }

    return try runCommandWithProgrammaticProvider(
        allocator,
        rpc,
        &derived_args,
        writer,
        programmatic_provider,
    );
}

fn summarizeWalletCoinBalances(
    allocator: std.mem.Allocator,
    owner: []const u8,
    page: client.coin_result.OwnedCoinPage,
    scanned_all_pages: bool,
    page_limit: ?u64,
) !OwnedWalletBalanceSummary {
    const Accumulator = struct {
        coin_type: []u8,
        total_balance: u128,
        coin_object_count: usize,

        fn deinit(self: *@This(), allocator_inner: std.mem.Allocator) void {
            allocator_inner.free(self.coin_type);
        }
    };

    var accumulators = std.ArrayList(Accumulator){};
    defer {
        for (accumulators.items) |*entry| entry.deinit(allocator);
        accumulators.deinit(allocator);
    }

    for (page.entries) |entry| {
        const coin_type = entry.coin_type orelse continue;
        const balance_text = entry.balance orelse continue;
        const balance = std.fmt.parseInt(u128, balance_text, 10) catch continue;

        var found = false;
        for (accumulators.items) |*current| {
            if (!std.mem.eql(u8, current.coin_type, coin_type)) continue;
            current.total_balance += balance;
            current.coin_object_count += 1;
            found = true;
            break;
        }
        if (found) continue;

        try accumulators.append(allocator, .{
            .coin_type = try allocator.dupe(u8, coin_type),
            .total_balance = balance,
            .coin_object_count = 1,
        });
    }

    const entries = try allocator.alloc(OwnedWalletCoinBalanceEntry, accumulators.items.len);
    errdefer allocator.free(entries);

    for (accumulators.items, 0..) |entry, index| {
        entries[index] = .{
            .coin_type = try allocator.dupe(u8, entry.coin_type),
            .total_balance = try std.fmt.allocPrint(allocator, "{d}", .{entry.total_balance}),
            .coin_object_count = entry.coin_object_count,
        };
    }

    return .{
        .owner = try allocator.dupe(u8, owner),
        .coin_balances = entries,
        .scanned_all_pages = scanned_all_pages,
        .has_next_page = page.has_next_page,
        .next_cursor = if (page.next_cursor) |value| try allocator.dupe(u8, value) else null,
        .page_limit = page_limit,
    };
}

fn parseBalanceCoinObjectCount(value: ?std.json.Value) ?usize {
    const current = value orelse return null;
    return switch (current) {
        .integer => |integer| if (integer >= 0) @intCast(integer) else null,
        .string => |text| std.fmt.parseInt(usize, text, 10) catch null,
        else => null,
    };
}

fn appendWalletBalanceEntryFromJsonValue(
    allocator: std.mem.Allocator,
    entries: *std.ArrayList(OwnedWalletCoinBalanceEntry),
    value: std.json.Value,
) !void {
    if (value != .object) return error.InvalidResponse;

    const coin_type_value = value.object.get("coinType") orelse return error.InvalidResponse;
    const total_balance_value = value.object.get("totalBalance") orelse return error.InvalidResponse;
    if (coin_type_value != .string or total_balance_value != .string) return error.InvalidResponse;

    try entries.append(allocator, .{
        .coin_type = try allocator.dupe(u8, coin_type_value.string),
        .total_balance = try allocator.dupe(u8, total_balance_value.string),
        .coin_object_count = parseBalanceCoinObjectCount(value.object.get("coinObjectCount")) orelse 0,
    });
}

fn summarizeWalletBalanceRpcResponse(
    allocator: std.mem.Allocator,
    owner: []const u8,
    response_json: []const u8,
) !OwnedWalletBalanceSummary {
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, response_json, .{});
    defer parsed.deinit();

    const root_result = if (parsed.value == .object)
        parsed.value.object.get("result") orelse parsed.value
    else
        parsed.value;

    var entries = std.ArrayList(OwnedWalletCoinBalanceEntry){};
    errdefer {
        for (entries.items) |*entry| entry.deinit(allocator);
        entries.deinit(allocator);
    }

    switch (root_result) {
        .array => |array| {
            for (array.items) |entry_value| {
                try appendWalletBalanceEntryFromJsonValue(allocator, &entries, entry_value);
            }
        },
        .object => {
            try appendWalletBalanceEntryFromJsonValue(allocator, &entries, root_result);
        },
        else => return error.InvalidResponse,
    }

    return .{
        .owner = try allocator.dupe(u8, owner),
        .coin_balances = try entries.toOwnedSlice(allocator),
        .scanned_all_pages = true,
        .has_next_page = false,
        .next_cursor = null,
        .page_limit = null,
    };
}

fn printBalanceSummaryForOwner(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    writer: anytype,
    owner: []const u8,
    args: *const cli.ParsedArgs,
) !void {
    if (args.account_resources_limit == null) {
        const response = if (args.account_coin_type) |coin_type|
            try rpc.getBalance(owner, coin_type)
        else
            try rpc.getAllBalances(owner);
        defer rpc.allocator.free(response);

        var summary = try summarizeWalletBalanceRpcResponse(
            allocator,
            owner,
            response,
        );
        defer summary.deinit(allocator);
        try printStructuredJson(writer, summary, args.pretty);
        return;
    }

    const coin_query: client.rpc_client.CoinQuery = .{
        .all = .{
            .owner = owner,
            .request = .{
                .coin_type = args.account_coin_type,
                .limit = args.account_resources_limit,
            },
        },
    };

    var result = try rpc.runResourceQueryAction(
        allocator,
        .{
            .coins = coin_query,
        },
        .summarize,
    );
    defer result.deinit(allocator);

    var summary = switch (result) {
        .summarized => |value| switch (value) {
            .coins => |page| try summarizeWalletCoinBalances(
                allocator,
                owner,
                page,
                true,
                args.account_resources_limit,
            ),
            else => return error.InvalidCli,
        },
        else => return error.InvalidCli,
    };
    defer summary.deinit(allocator);

    try printStructuredJson(writer, summary, args.pretty);
}

fn writeJsonFieldPrefix(writer: anytype, has_fields: *bool, name: []const u8) !void {
    if (has_fields.*) try writer.writeAll(",");
    has_fields.* = true;
    try writer.print("\"{s}\":", .{name});
}

fn writeJsonStringArrayField(
    writer: anytype,
    has_fields: *bool,
    name: []const u8,
    items: []const []const u8,
) !void {
    if (items.len == 0) return;
    try writeJsonFieldPrefix(writer, has_fields, name);
    try writer.writeAll("[");
    for (items, 0..) |item, index| {
        if (index != 0) try writer.writeAll(",");
        try writer.print("{f}", .{std.json.fmt(item, .{})});
    }
    try writer.writeAll("]");
}

fn buildRequestArtifactJsonFromArgs(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) ![]u8 {
    if (cli.hasProgrammaticTxContext(args)) {
        try cli.validateProgrammaticTxInput(args);
    }
    if (!cli.supportsProgrammableInput(args)) return error.InvalidCli;

    const commands_json = try tx_builder.resolveCommands(allocator, commandSourceFromArgs(args));
    defer allocator.free(commands_json);

    const sender = try @import("./tx_pipeline.zig").resolvedTxBuildSenderFromArgs(allocator, args);
    defer if (sender) |value| allocator.free(value);

    var output = std.ArrayList(u8){};
    errdefer output.deinit(allocator);
    const writer = output.writer(allocator);

    var has_fields = false;
    try writer.writeAll("{");
    try writeJsonFieldPrefix(writer, &has_fields, "commands");
    try writer.writeAll(commands_json);
    if (sender) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "sender");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
    }
    if (args.tx_build_gas_budget) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "gasBudget");
        try writer.print("{d}", .{value});
    }
    if (args.tx_build_gas_price) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "gasPrice");
        try writer.print("{d}", .{value});
    }
    if (args.tx_build_gas_payment) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "gasPayment");
        try writer.writeAll(value);
    }
    if (args.tx_options) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "options");
        try writer.writeAll(value);
    }
    if (args.tx_build_auto_gas_payment) {
        try writeJsonFieldPrefix(writer, &has_fields, "autoGasPayment");
        try writer.writeAll("true");
    }
    if (args.tx_build_auto_gas_budget) {
        try writeJsonFieldPrefix(writer, &has_fields, "autoGasBudget");
        try writer.writeAll("true");
    }
    if (args.tx_build_gas_payment_min_balance) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "gasPaymentMinBalance");
        try writer.print("{d}", .{value});
    }
    if (args.from_keystore) {
        try writeJsonFieldPrefix(writer, &has_fields, "fromKeystore");
        try writer.writeAll("true");
    }
    try writeJsonStringArrayField(writer, &has_fields, "signers", args.signers.items);
    try writeJsonStringArrayField(writer, &has_fields, "signatures", args.signatures.items);
    if (args.tx_send_wait) {
        try writeJsonFieldPrefix(writer, &has_fields, "wait");
        try writer.writeAll("true");
    }
    if (args.tx_send_summarize) {
        try writeJsonFieldPrefix(writer, &has_fields, "summarize");
        try writer.writeAll("true");
    }
    if (args.tx_send_observe) {
        try writeJsonFieldPrefix(writer, &has_fields, "observe");
        try writer.writeAll("true");
    }
    if (args.confirm_timeout_ms) |value| {
        try writeJsonFieldPrefix(writer, &has_fields, "confirmTimeoutMs");
        try writer.print("{d}", .{value});
    }
    if (args.confirm_poll_ms != 2_000) {
        try writeJsonFieldPrefix(writer, &has_fields, "confirmPollMs");
        try writer.print("{d}", .{args.confirm_poll_ms});
    }
    try writer.writeAll("}");

    return try output.toOwnedSlice(allocator);
}

fn buildRequestInspectSummaryJson(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) ![]u8 {
    const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
    defer allocator.free(request_json);

    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, request_json, .{});
    defer parsed.deinit();
    const request_object = parsed.value.object;
    const commands = request_object.get("commands") orelse return error.InvalidCli;
    if (commands != .array) return error.InvalidCli;

    var output = std.ArrayList(u8){};
    errdefer output.deinit(allocator);
    const writer = output.writer(allocator);

    try writer.writeAll("{");
    try writer.writeAll("\"data_kind\":\"request_artifact\"");
    try writer.print(",\"source_kind\":{f}", .{std.json.fmt(if (args.tx_build_package != null and args.tx_build_module != null and args.tx_build_function != null and args.tx_build_commands == null and args.tx_build_command_items.items.len == 0) "move_call" else "commands", .{})});
    try writer.print(",\"command_count\":{d}", .{commands.array.items.len});
    try writer.writeAll(",\"command_kinds\":[");
    for (commands.array.items, 0..) |entry, index| {
        if (index != 0) try writer.writeAll(",");
        if (entry != .object) return error.InvalidCli;
        const kind = entry.object.get("kind") orelse return error.InvalidCli;
        if (kind != .string) return error.InvalidCli;
        try writer.print("{f}", .{std.json.fmt(kind.string, .{})});
    }
    try writer.writeAll("]");
    if (request_object.get("sender")) |sender| {
        try writer.writeAll(",\"has_sender\":true,\"sender\":");
        try writer.print("{f}", .{std.json.fmt(sender, .{})});
    } else {
        try writer.writeAll(",\"has_sender\":false,\"sender\":null");
    }
    if (request_object.get("gasBudget")) |value| {
        try writer.writeAll(",\"gas_budget\":");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
    } else {
        try writer.writeAll(",\"gas_budget\":null");
    }
    if (request_object.get("gasPrice")) |value| {
        try writer.writeAll(",\"gas_price\":");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
    } else {
        try writer.writeAll(",\"gas_price\":null");
    }
    try writer.print(",\"has_gas_payment\":{any}", .{request_object.get("gasPayment") != null});
    try writer.print(",\"has_options\":{any}", .{request_object.get("options") != null});
    try writer.print(",\"auto_gas_payment\":{any}", .{request_object.get("autoGasPayment") != null});
    try writer.print(",\"auto_gas_budget\":{any}", .{request_object.get("autoGasBudget") != null});
    try writer.print(",\"from_keystore\":{any}", .{request_object.get("fromKeystore") != null});
    try writer.print(",\"wait_for_confirmation\":{any}", .{request_object.get("wait") != null});
    try writer.print(",\"summarize_response\":{any}", .{request_object.get("summarize") != null});
    try writer.print(",\"observe_response\":{any}", .{request_object.get("observe") != null});
    if (request_object.get("signers")) |signers| {
        if (signers != .array) return error.InvalidCli;
        try writer.print(",\"signer_count\":{d}", .{signers.array.items.len});
    } else {
        try writer.writeAll(",\"signer_count\":0");
    }
    if (request_object.get("signatures")) |signatures| {
        if (signatures != .array) return error.InvalidCli;
        try writer.print(",\"signature_count\":{d}", .{signatures.array.items.len});
    } else {
        try writer.writeAll(",\"signature_count\":0");
    }
    try writer.writeAll(",\"request\":");
    try writer.writeAll(request_json);
    try writer.writeAll("}");

    return try output.toOwnedSlice(allocator);
}

fn resolvedWalletIntentNetwork(args: *const cli.ParsedArgs) []const u8 {
    return args.intent_network orelse wallet_intent.defaultNetworkLabelForRpcUrl(args.rpc_url);
}

fn resolvedWalletIntentExecutionMode(
    args: *const cli.ParsedArgs,
    default_mode: []const u8,
) ![]const u8 {
    const mode = args.intent_execution_mode orelse default_mode;
    try wallet_intent.validateExecutionMode(mode);
    return mode;
}

fn anyExtraIntentPolicyFields(args: *const cli.ParsedArgs) bool {
    return args.intent_policy_recurring_limit != null or
        args.intent_policy_recurring_interval_ms != null or
        args.intent_policy_recipient_allowlist_json != null or
        args.intent_policy_protocol_allowlist_json != null;
}

fn parsePolicyArrayJson(
    allocator: std.mem.Allocator,
    raw_json: []const u8,
) !std.json.Parsed(std.json.Value) {
    const parsed = try std.json.parseFromSlice(std.json.Value, allocator, raw_json, .{});
    if (parsed.value != .array) {
        parsed.deinit();
        return error.InvalidCli;
    }
    return parsed;
}

fn isWalletPolicyMergeReservedKey(key: []const u8) bool {
    return std.mem.eql(u8, key, "recurring_limit") or
        std.mem.eql(u8, key, "recurringLimit") or
        std.mem.eql(u8, key, "recipient_allowlist") or
        std.mem.eql(u8, key, "recipientAllowlist") or
        std.mem.eql(u8, key, "protocol_allowlist") or
        std.mem.eql(u8, key, "protocolAllowlist");
}

fn appendMergedWalletPolicyGenericFields(
    target: *std.json.ObjectMap,
    object: std.json.ObjectMap,
) !void {
    var iterator = object.iterator();
    while (iterator.next()) |entry| {
        if (isWalletPolicyMergeReservedKey(entry.key_ptr.*)) continue;
        try target.put(entry.key_ptr.*, entry.value_ptr.*);
    }
}

fn writeMergedWalletPolicyWithBase(
    allocator: std.mem.Allocator,
    writer: anytype,
    base_policy_json: ?[]const u8,
    args: *const cli.ParsedArgs,
) !void {
    const has_extra_fields = anyExtraIntentPolicyFields(args);
    const override_policy_json = args.intent_policy_json;
    if (base_policy_json == null and override_policy_json == null and !has_extra_fields) {
        try writer.writeAll("null");
        return;
    }

    var parsed_base: ?std.json.Parsed(std.json.Value) = null;
    defer if (parsed_base) |*value| value.deinit();
    if (base_policy_json) |value| {
        parsed_base = try std.json.parseFromSlice(std.json.Value, allocator, value, .{});
        if (parsed_base.?.value != .object) return error.InvalidCli;
    }

    var parsed_override: ?std.json.Parsed(std.json.Value) = null;
    defer if (parsed_override) |*value| value.deinit();
    if (override_policy_json) |value| {
        parsed_override = try std.json.parseFromSlice(std.json.Value, allocator, value, .{});
        if (parsed_override.?.value != .object) return error.InvalidCli;
    }

    var parsed_recipients: ?std.json.Parsed(std.json.Value) = null;
    defer if (parsed_recipients) |*value| value.deinit();
    if (args.intent_policy_recipient_allowlist_json) |value| {
        parsed_recipients = try parsePolicyArrayJson(allocator, value);
    }

    var parsed_protocols: ?std.json.Parsed(std.json.Value) = null;
    defer if (parsed_protocols) |*value| value.deinit();
    if (args.intent_policy_protocol_allowlist_json) |value| {
        parsed_protocols = try parsePolicyArrayJson(allocator, value);
    }

    var merged = std.json.ObjectMap.init(allocator);
    defer merged.deinit();

    if (parsed_base) |base| {
        try appendMergedWalletPolicyGenericFields(&merged, base.value.object);
    }
    if (parsed_override) |override| {
        try appendMergedWalletPolicyGenericFields(&merged, override.value.object);
    }

    var recurring_limit_object: ?std.json.ObjectMap = null;
    defer if (recurring_limit_object) |*value| value.deinit();

    if (args.intent_policy_recurring_limit) |amount| {
        recurring_limit_object = std.json.ObjectMap.init(allocator);
        try recurring_limit_object.?.put("amount", .{ .integer = @as(i64, @intCast(amount)) });
        try recurring_limit_object.?.put("interval_ms", .{ .integer = @as(i64, @intCast(args.intent_policy_recurring_interval_ms.?)) });
        try merged.put("recurring_limit", .{ .object = recurring_limit_object.? });
    } else if (parsed_override) |override| {
        if (jsonObjectFieldAny(override.value.object, &.{ "recurring_limit", "recurringLimit" })) |value| {
            try merged.put("recurring_limit", value);
        } else if (parsed_base) |base| {
            if (jsonObjectFieldAny(base.value.object, &.{ "recurring_limit", "recurringLimit" })) |value| {
                try merged.put("recurring_limit", value);
            }
        }
    } else if (parsed_base) |base| {
        if (jsonObjectFieldAny(base.value.object, &.{ "recurring_limit", "recurringLimit" })) |value| {
            try merged.put("recurring_limit", value);
        }
    }

    if (parsed_recipients) |value| {
        try merged.put("recipient_allowlist", value.value);
    } else if (parsed_override) |override| {
        if (jsonObjectFieldAny(override.value.object, &.{ "recipient_allowlist", "recipientAllowlist" })) |value| {
            try merged.put("recipient_allowlist", value);
        } else if (parsed_base) |base| {
            if (jsonObjectFieldAny(base.value.object, &.{ "recipient_allowlist", "recipientAllowlist" })) |value| {
                try merged.put("recipient_allowlist", value);
            }
        }
    } else if (parsed_base) |base| {
        if (jsonObjectFieldAny(base.value.object, &.{ "recipient_allowlist", "recipientAllowlist" })) |value| {
            try merged.put("recipient_allowlist", value);
        }
    }

    if (parsed_protocols) |value| {
        try merged.put("protocol_allowlist", value.value);
    } else if (parsed_override) |override| {
        if (jsonObjectFieldAny(override.value.object, &.{ "protocol_allowlist", "protocolAllowlist" })) |value| {
            try merged.put("protocol_allowlist", value);
        } else if (parsed_base) |base| {
            if (jsonObjectFieldAny(base.value.object, &.{ "protocol_allowlist", "protocolAllowlist" })) |value| {
                try merged.put("protocol_allowlist", value);
            }
        }
    } else if (parsed_base) |base| {
        if (jsonObjectFieldAny(base.value.object, &.{ "protocol_allowlist", "protocolAllowlist" })) |value| {
            try merged.put("protocol_allowlist", value);
        }
    }

    try writer.print("{f}", .{std.json.fmt(std.json.Value{ .object = merged }, .{})});
}

fn writeMergedWalletPolicy(
    allocator: std.mem.Allocator,
    writer: anytype,
    args: *const cli.ParsedArgs,
) !void {
    try writeMergedWalletPolicyWithBase(allocator, writer, null, args);
}

fn buildMergedWalletPolicyJson(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
) !?[]u8 {
    return try buildMergedWalletPolicyJsonWithBase(allocator, null, args);
}

fn buildMergedWalletPolicyJsonWithBase(
    allocator: std.mem.Allocator,
    base_policy_json: ?[]const u8,
    args: *const cli.ParsedArgs,
) !?[]u8 {
    if (base_policy_json == null and args.intent_policy_json == null and !anyExtraIntentPolicyFields(args)) return null;

    var output = std.ArrayList(u8){};
    errdefer output.deinit(allocator);
    try writeMergedWalletPolicyWithBase(allocator, output.writer(allocator), base_policy_json, args);
    return try output.toOwnedSlice(allocator);
}

fn buildWalletIntentJsonFromArgs(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    default_execution_mode: []const u8,
) ![]u8 {
    const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
    defer allocator.free(request_json);

    const summary_json = try buildRequestInspectSummaryJson(allocator, args);
    defer allocator.free(summary_json);

    const request = try std.json.parseFromSlice(std.json.Value, allocator, request_json, .{});
    defer request.deinit();
    if (request.value != .object) return error.InvalidCli;

    var delegated_session = try resolveDelegatedSessionArtifactSummary(allocator, args);
    defer if (delegated_session) |*value| value.deinit(allocator);

    const effective_policy_json = try buildMergedWalletPolicyJsonWithBase(
        allocator,
        if (delegated_session) |value| value.policy_json else null,
        args,
    );
    defer if (effective_policy_json) |value| allocator.free(value);

    const network = resolvedWalletIntentNetwork(args);
    const execution_mode = try resolvedWalletIntentExecutionMode(args, default_execution_mode);
    var output = std.ArrayList(u8){};
    errdefer output.deinit(allocator);
    const writer = output.writer(allocator);

    try writer.writeAll("{");
    try writer.writeAll("\"artifact_kind\":\"wallet_intent\"");
    try writer.print(",\"schema_version\":{d}", .{wallet_intent.schema_version});
    try writer.print(",\"network\":{f}", .{std.json.fmt(network, .{})});
    try writer.print(",\"execution_mode\":{f}", .{std.json.fmt(execution_mode, .{})});
    try writer.writeAll(",\"sender\":");
    if (request.value.object.get("sender")) |sender| {
        try writer.print("{f}", .{std.json.fmt(sender, .{})});
    } else {
        try writer.writeAll("null");
    }
    try writer.writeAll(",\"valid_after_ms\":");
    if (args.request_valid_after_ms) |value| {
        try writer.print("{d}", .{value});
    } else {
        try writer.writeAll("null");
    }
    try writer.writeAll(",\"valid_before_ms\":");
    if (args.request_valid_before_ms) |value| {
        try writer.print("{d}", .{value});
    } else {
        try writer.writeAll("null");
    }
    try writer.writeAll(",\"correlation_id\":");
    if (args.request_correlation_id) |value| {
        try writer.print("{f}", .{std.json.fmt(value, .{})});
    } else {
        try writer.writeAll("null");
    }
    try writer.writeAll(",\"request\":");
    try writer.writeAll(request_json);
    try writer.writeAll(",\"request_summary\":");
    try writer.writeAll(summary_json);
    try writer.writeAll(",\"payment\":");
    try writeResolvedRequestPaymentMetadata(writer, args);
    try writer.writeAll(",\"concurrency\":");
    try writeResolvedRequestConcurrencyMetadata(writer, args);
    try writer.writeAll(",\"delegated_session\":");
    try writeDelegatedSessionArtifactMetadata(
        writer,
        if (delegated_session) |*value| value else null,
        args.request_delegated_session_json,
    );
    try writer.writeAll(",\"sponsor\":{");
    try writeResolvedRequestSponsorContract(writer, args);
    try writer.writeAll("}");
    try writer.writeAll(",\"policy\":");
    if (effective_policy_json) |value| {
        try writer.writeAll(value);
    } else {
        try writer.writeAll("null");
    }
    try writer.writeAll("}");

    return try output.toOwnedSlice(allocator);
}

fn resolvedRequestSponsorMode(args: *const cli.ParsedArgs) ![]const u8 {
    const mode = args.request_sponsor_mode orelse "optional";
    if (std.mem.eql(u8, mode, "direct") or std.mem.eql(u8, mode, "optional") or std.mem.eql(u8, mode, "required")) {
        return mode;
    }
    return error.InvalidCli;
}

fn resolvedRequestSponsorGasSourcePreference(args: *const cli.ParsedArgs) ![]const u8 {
    if (args.request_sponsor_gas_source_preference) |value| return value;

    const sponsor_mode = try resolvedRequestSponsorMode(args);
    if (std.mem.eql(u8, sponsor_mode, "direct")) return "sender";
    if (std.mem.eql(u8, sponsor_mode, "required")) return "sponsor";
    return "prefer_sponsor";
}

fn resolvedRequestSponsorRefusalFallback(args: *const cli.ParsedArgs) ![]const u8 {
    if (args.request_sponsor_refusal_fallback) |value| return value;

    const sponsor_mode = try resolvedRequestSponsorMode(args);
    if (std.mem.eql(u8, sponsor_mode, "required")) return "fail_closed";
    return "fallback_to_sender";
}

fn writeResolvedRequestSponsorContract(
    writer: anytype,
    args: *const cli.ParsedArgs,
) !void {
    const sponsor_mode = try resolvedRequestSponsorMode(args);
    const gas_source_preference = try resolvedRequestSponsorGasSourcePreference(args);
    const refusal_fallback = try resolvedRequestSponsorRefusalFallback(args);

    try writer.writeAll("\"mode\":");
    try writer.print("{f}", .{std.json.fmt(sponsor_mode, .{})});
    try writer.writeAll(",\"policy_metadata\":");
    if (args.request_sponsor_policy) |value| {
        try writer.writeAll(value);
    } else {
        try writer.writeAll("null");
    }
    try writer.writeAll(",\"gas_source_preference\":");
    try writer.print("{f}", .{std.json.fmt(gas_source_preference, .{})});
    try writer.writeAll(",\"refusal_fallback\":");
    try writer.print("{f}", .{std.json.fmt(refusal_fallback, .{})});
}

fn hasRequestPaymentMetadata(args: *const cli.ParsedArgs) bool {
    return args.request_payment_reference != null or
        args.request_payment_memo != null or
        args.request_invoice_reference != null or
        args.request_reconciliation_group != null;
}

fn writeResolvedRequestPaymentMetadata(
    writer: anytype,
    args: *const cli.ParsedArgs,
) !void {
    if (!hasRequestPaymentMetadata(args)) {
        try writer.writeAll("null");
        return;
    }

    try writer.writeAll("{");
    var wrote_field = false;

    if (args.request_payment_reference) |value| {
        if (wrote_field) try writer.writeAll(",");
        try writer.writeAll("\"payment_reference\":");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
        wrote_field = true;
    }
    if (args.request_payment_memo) |value| {
        if (wrote_field) try writer.writeAll(",");
        try writer.writeAll("\"memo\":");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
        wrote_field = true;
    }
    if (args.request_invoice_reference) |value| {
        if (wrote_field) try writer.writeAll(",");
        try writer.writeAll("\"invoice_reference\":");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
        wrote_field = true;
    }
    if (args.request_reconciliation_group) |value| {
        if (wrote_field) try writer.writeAll(",");
        try writer.writeAll("\"reconciliation_group\":");
        try writer.print("{f}", .{std.json.fmt(value, .{})});
    }

    try writer.writeAll("}");
}

fn hasRequestConcurrencyMetadata(args: *const cli.ParsedArgs) bool {
    return args.request_execution_lane != null or
        args.request_gas_lane != null or
        args.request_conflict_keys_json != null or
        args.request_conflict_strategy != null;
}

fn resolvedRequestConflictStrategy(args: *const cli.ParsedArgs) []const u8 {
    return args.request_conflict_strategy orelse "serialize_same_lane";
}

fn writeResolvedRequestConcurrencyMetadata(
    writer: anytype,
