fn replaceOptionalRequestStateField(
    allocator: std.mem.Allocator,
    field: *?[]u8,
    value: ?[]const u8,
) !void {
    if (field.*) |existing| allocator.free(existing);
    field.* = try duplicateOptionalSlice(allocator, value);
}

fn resolvedRequestLifecycleEntryId(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    prefix: []const u8,
) ![]u8 {
    if (args.request_correlation_id) |value| return try allocator.dupe(u8, value);
    return try std.fmt.allocPrint(allocator, "{s}-{d}", .{ prefix, std.time.milliTimestamp() });
}

fn upsertRequestLifecycleEntry(
    allocator: std.mem.Allocator,
    entry_id: []const u8,
    kind: []const u8,
    next_state: []const u8,
    request_json: ?[]const u8,
    artifact_json: ?[]const u8,
    digest: ?[]const u8,
    correlation_id: ?[]const u8,
    submit_count_delta: u64,
    last_error: ?[]const u8,
) !void {
    const state_path = try request_state.resolveDefaultRequestStatePath(allocator);
    defer if (state_path) |value| allocator.free(value);
    if (state_path == null) return;

    var state = try request_state.loadDefaultRequestState(allocator);
    defer state.deinit(allocator);

    const now_ms = std.time.milliTimestamp();
    if (findRequestStateEntryIndex(&state, entry_id)) |index| {
        var entry = &state.entries[index];
        allocator.free(entry.kind);
        entry.kind = try allocator.dupe(u8, kind);
        try setRequestStateEntryStateAt(allocator, entry, next_state, now_ms);
        try replaceOptionalRequestStateField(allocator, &entry.request_json, request_json);
        try replaceOptionalRequestStateField(allocator, &entry.artifact_json, artifact_json);
        try replaceOptionalRequestStateField(allocator, &entry.digest, digest);
        try replaceOptionalRequestStateField(allocator, &entry.correlation_id, correlation_id);
        try replaceOptionalRequestStateField(allocator, &entry.last_error, last_error);
        entry.submit_count += submit_count_delta;
    } else {
        const entry = request_state.OwnedRequestEntry{
            .id = try allocator.dupe(u8, entry_id),
            .kind = try allocator.dupe(u8, kind),
            .state = try allocator.dupe(u8, next_state),
            .request_json = try duplicateOptionalSlice(allocator, request_json),
            .artifact_json = try duplicateOptionalSlice(allocator, artifact_json),
            .digest = try duplicateOptionalSlice(allocator, digest),
            .correlation_id = try duplicateOptionalSlice(allocator, correlation_id),
            .created_at_ms = now_ms,
            .updated_at_ms = now_ms,
            .submit_count = submit_count_delta,
            .last_error = try duplicateOptionalSlice(allocator, last_error),
        };
        try appendRequestStateEntry(allocator, &state, entry);
    }

    try request_state.writeDefaultRequestState(allocator, &state);
}

fn isRequestChallengePromptValue(value: std.json.Value) bool {
    if (value != .object) return false;
    return value.object.get("challenge") != null and
        (value.object.get("account_address") != null or value.object.get("accountAddress") != null);
}

const RequestLifecycleOutputMode = enum {
    dry_run,
    sign,
    send,
};

const OwnedRequestLifecycleOutputSummary = struct {
    is_challenge_prompt: bool = false,
    next_state: ?[]const u8 = null,
    digest: ?[]u8 = null,

    fn deinit(self: *OwnedRequestLifecycleOutputSummary, allocator: std.mem.Allocator) void {
        if (self.digest) |value| allocator.free(value);
    }
};

fn summarizeRequestLifecycleOutput(
    allocator: std.mem.Allocator,
    output_json: []const u8,
    mode: RequestLifecycleOutputMode,
) !OwnedRequestLifecycleOutputSummary {
    const parsed = std.json.parseFromSlice(std.json.Value, allocator, output_json, .{}) catch {
        return .{
            .is_challenge_prompt = false,
            .next_state = switch (mode) {
                .dry_run => "resolved",
                .sign => "signed",
                .send => "submitted",
            },
            .digest = null,
        };
    };
    defer parsed.deinit();

    if (isRequestChallengePromptValue(parsed.value)) {
        return .{ .is_challenge_prompt = true };
    }

    const digest = if (jsonFindFirstStringField(parsed.value, "digest")) |value|
        try allocator.dupe(u8, value)
    else
        null;

    return .{
        .is_challenge_prompt = false,
        .next_state = switch (mode) {
            .dry_run => "resolved",
            .sign => "signed",
            .send => if (jsonFindFirstStringField(parsed.value, "status")) |status|
                if (std.mem.eql(u8, status, "success"))
                    "confirmed"
                else if (std.mem.eql(u8, status, "failure"))
                    "failed"
                else
                    "submitted"
            else
                "submitted",
        },
        .digest = digest,
    };
}

fn ownedRequestLifecycleErrorMessage(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    err: anyerror,
) ![]u8 {
    if (err == client.ClientError.RpcError) {
        if (rpc.getLastError()) |last_error| {
            return try allocator.dupe(u8, last_error.message);
        }
    }
    return try allocator.dupe(u8, @errorName(err));
}

fn ownedRequestLifecycleStatusMessage(
    allocator: std.mem.Allocator,
    value: std.json.Value,
) !?[]u8 {
    if (jsonFindFirstStringField(value, "status_error")) |message| {
        return try allocator.dupe(u8, message);
    }
    if (jsonFindFirstStringField(value, "error")) |message| {
        return try allocator.dupe(u8, message);
    }
    if (jsonFindFirstStringField(value, "message")) |message| {
        return try allocator.dupe(u8, message);
    }
    return null;
}

fn storeScheduledRequestEntry(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    schedule_id: []const u8,
    request_json: []const u8,
    schedule_json: []const u8,
) !void {
    var state = try request_state.loadDefaultRequestState(allocator);
    defer state.deinit(allocator);

    const now_ms = std.time.milliTimestamp();

    if (args.request_schedule_replace_id) |replace_id| {
        if (findRequestStateEntryIndex(&state, replace_id)) |index| {
            try setRequestStateEntryStateAt(allocator, &state.entries[index], "replaced", now_ms);
        }
    }

    const entry = request_state.OwnedRequestEntry{
        .id = try allocator.dupe(u8, schedule_id),
        .kind = try allocator.dupe(u8, "schedule_job"),
        .state = try allocator.dupe(u8, "scheduled"),
        .request_json = try allocator.dupe(u8, request_json),
        .artifact_json = try allocator.dupe(u8, schedule_json),
        .digest = null,
        .correlation_id = try duplicateOptionalSlice(allocator, args.request_correlation_id),
        .created_at_ms = now_ms,
        .updated_at_ms = now_ms,
        .submit_count = 0,
        .last_error = null,
    };

    if (findRequestStateEntryIndex(&state, schedule_id)) |index| {
        replaceRequestStateEntryAt(allocator, &state, index, entry);
    } else {
        try appendRequestStateEntry(allocator, &state, entry);
    }

    try request_state.writeDefaultRequestState(allocator, &state);
}

fn buildDerivedRequestCommandArgs(
    allocator: std.mem.Allocator,
    args: *const cli.ParsedArgs,
    command: cli.Command,
    request_json: []const u8,
) !cli.ParsedArgs {
    var derived = cli.ParsedArgs{
        .command = command,
        .has_command = true,
        .pretty = args.pretty,
        .confirm_timeout_ms = args.confirm_timeout_ms,
        .confirm_poll_ms = args.confirm_poll_ms,
        .tx_send_wait = args.tx_send_wait,
        .tx_send_summarize = args.tx_send_summarize,
        .tx_send_observe = args.tx_send_observe,
    };
    errdefer derived.deinit(allocator);

    try cli.applyProgrammaticRequestArtifact(allocator, &derived, request_json);

    derived.pretty = args.pretty;
    derived.confirm_timeout_ms = args.confirm_timeout_ms;
    derived.confirm_poll_ms = args.confirm_poll_ms;
    if (args.tx_send_wait) derived.tx_send_wait = true;
    if (args.tx_send_summarize) derived.tx_send_summarize = true;
    if (args.tx_send_observe) {
        derived.tx_send_observe = true;
        derived.tx_send_summarize = false;
    }
    if (args.from_keystore) derived.from_keystore = true;
    if (args.tx_session_response) |raw| {
        const owned = try allocator.dupe(u8, raw);
        derived.owned_tx_session_response = owned;
        derived.tx_session_response = owned;
    }
    if (args.tx_provider_config) |raw| {
        const owned = try allocator.dupe(u8, raw);
        derived.owned_tx_provider_config = owned;
        derived.tx_provider_config = owned;
    }
    for (args.signatures.items) |signature| {
        const owned = try allocator.dupe(u8, signature);
        try derived.signatures.append(allocator, owned);
        try derived.owned_signatures.append(allocator, owned);
    }
    for (args.signers.items) |signer| {
        const owned = try allocator.dupe(u8, signer);
        try derived.signers.append(allocator, owned);
        try derived.owned_signers.append(allocator, owned);
    }

    return derived;
}

fn updateTrackedRequestEntryFromStatusOutput(
    allocator: std.mem.Allocator,
    entry: *request_state.OwnedRequestEntry,
    output_json: []const u8,
) !void {
    const now_ms = std.time.milliTimestamp();
    if (std.json.parseFromSlice(std.json.Value, allocator, output_json, .{})) |parsed| {
        defer parsed.deinit();
        if (jsonFindFirstStringField(parsed.value, "digest")) |digest| {
            try replaceOptionalRequestStateField(allocator, &entry.digest, digest);
        }
        if (jsonFindFirstStringField(parsed.value, "status")) |status| {
            try setRequestStateEntryStateAt(
                allocator,
                entry,
                if (std.mem.eql(u8, status, "success"))
                    "confirmed"
                else if (std.mem.eql(u8, status, "failure"))
                    "failed"
                else
                    "submitted",
                now_ms,
            );
            if (std.mem.eql(u8, status, "success")) {
                try replaceOptionalRequestStateField(allocator, &entry.last_error, null);
            } else if (std.mem.eql(u8, status, "failure")) {
                const failure_message = (try ownedRequestLifecycleStatusMessage(allocator, parsed.value)) orelse
                    try allocator.dupe(u8, "transaction status failure");
                defer allocator.free(failure_message);
                try replaceOptionalRequestStateField(allocator, &entry.last_error, failure_message);
            }
        } else {
            entry.updated_at_ms = now_ms;
        }
    } else |_| {
        entry.updated_at_ms = now_ms;
    }
}

fn runTrackedRequestStatusLikeCommand(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    writer: anytype,
    effective_programmatic_provider: ?client.tx_request_builder.AccountProvider,
    tx_command: cli.Command,
) anyerror!void {
    const target = args.request_entry_id orelse return error.InvalidCli;
    var state = try request_state.loadDefaultRequestState(allocator);
    defer state.deinit(allocator);

    const matched_index = findRequestStateEntryIndex(&state, target);
    const status_digest = if (matched_index) |index|
        try allocator.dupe(u8, state.entries[index].digest orelse return error.InvalidCli)
    else
        try allocator.dupe(u8, target);
    defer allocator.free(status_digest);

    var derived_args = args.*;
    derived_args.command = tx_command;
    derived_args.tx_digest = status_digest;

    var output = std.ArrayList(u8){};
    defer output.deinit(allocator);
    try runCommandWithProgrammaticProvider(
        allocator,
        rpc,
        &derived_args,
        output.writer(allocator),
        effective_programmatic_provider,
    );

    if (matched_index) |index| {
        try updateTrackedRequestEntryFromStatusOutput(
            allocator,
            &state.entries[index],
            output.items,
        );
        try request_state.writeDefaultRequestState(allocator, &state);
    }

    try writer.writeAll(output.items);
}

fn jsonFindFirstStringField(value: std.json.Value, field_name: []const u8) ?[]const u8 {
    switch (value) {
        .string => return null,
        .array => |array| {
            for (array.items) |item| {
                if (jsonFindFirstStringField(item, field_name)) |found| return found;
            }
        },
        .object => |object| {
            if (object.get(field_name)) |field_value| {
                if (field_value == .string) return field_value.string;
            }
            var iterator = object.iterator();
            while (iterator.next()) |entry| {
                if (jsonFindFirstStringField(entry.value_ptr.*, field_name)) |found| return found;
            }
        },
        else => {},
    }
    return null;
}

fn printReadQuerySummary(
    writer: anytype,
    summary: client.rpc_client.ReadQuerySummary,
    pretty: bool,
) !void {
    switch (summary) {
        .account => |account| switch (account) {
            .list => |list| try printAccountEntries(writer, list.accounts),
            .info => |entry| try printAccountEntry(writer, entry),
        },
        .resources => |value| try printStructuredJson(writer, value, pretty),
        .coins => |value| try printStructuredJson(writer, value, pretty),
        .owned_objects => |value| try printStructuredJson(writer, value, pretty),
        .events => |value| try printStructuredJson(writer, value, pretty),
        .object => |object| switch (object) {
            .object => |value| try printStructuredJson(writer, value, pretty),
            .dynamic_fields => |value| try printStructuredJson(writer, value, pretty),
        },
        .move => |move| switch (move) {
            .function => |value| try printStructuredJson(writer, value, pretty),
            .module => |value| try printStructuredJson(writer, value, pretty),
            .package => |value| try printStructuredJson(writer, value, pretty),
        },
        .transaction => |value| try printStructuredJson(writer, value, pretty),
    }
}

fn printReadQueryActionResult(
    allocator: std.mem.Allocator,
    writer: anytype,
    result: client.rpc_client.ReadQueryActionResult,
    pretty: bool,
) !void {
    switch (result) {
        .raw => |response| try printResponse(allocator, writer, response, pretty),
        .summarized => |summary| try printReadQuerySummary(writer, summary, pretty),
        .observed => |observation| try printStructuredJson(writer, observation, pretty),
    }
}

fn printResourceQuerySummary(
    writer: anytype,
    summary: client.rpc_client.ResourceQuerySummary,
    pretty: bool,
) !void {
    switch (summary) {
        .coins => |value| try printStructuredJson(writer, value, pretty),
        .owned_objects => |value| try printStructuredJson(writer, value, pretty),
    }
}

fn printResourceQueryActionResult(
    allocator: std.mem.Allocator,
    writer: anytype,
    result: client.rpc_client.ResourceQueryActionResult,
    pretty: bool,
) !void {
    switch (result) {
        .raw => |response| try printResponse(allocator, writer, response, pretty),
        .summarized => |summary| try printResourceQuerySummary(writer, summary, pretty),
    }
}

pub fn runCommandWithProgrammaticProvider(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    writer: anytype,
    programmatic_provider: ?client.tx_request_builder.AccountProvider,
) !void {
    var owned_cli_provider: ?OwnedCliProgrammaticProvider = null;
    defer if (owned_cli_provider) |*value| value.deinit();

    const cli_provider = blk: {
        if (programmatic_provider != null) break :blk null;
        const raw = args.tx_provider_config orelse break :blk null;
        owned_cli_provider = try ownCliProgrammaticProvider(rpc, allocator, raw);
        break :blk owned_cli_provider.?.provider;
    };

    const base_programmatic_provider = if (cli.supportsProgrammableInput(args))
        resolvedProgrammaticProvider(args, programmatic_provider orelse cli_provider)
    else
        null;
    var owned_delegated_provider = try ownProgrammaticProviderWithDelegatedSession(
        allocator,
        args,
        base_programmatic_provider,
    );
    defer owned_delegated_provider.deinit(allocator);
    const effective_programmatic_provider = owned_delegated_provider.provider;

    switch (args.command) {
        .help => try cli.printUsage(writer),
        .version => {
            const version = @import("sui_client_zig").version;
            try writer.print("sui-zig-rpc-client {d}.{d}.{d}\n", .{ version.major, version.minor, version.patch });
        },
        .wallet_create => {
            const raw_key = try client.keystore.generateRawKeyString(allocator);
            defer allocator.free(raw_key);
            try runWalletCreateOrImport(allocator, args, writer, "wallet_created", raw_key);
        },
        .wallet_import => {
            const raw_key = args.wallet_private_key orelse return error.InvalidCli;
            try runWalletCreateOrImport(allocator, args, writer, "wallet_imported", raw_key);
        },
        .wallet_use => try runWalletUse(allocator, args, writer),
        .wallet_accounts => try runWalletAccounts(allocator, args, writer, false),
        .wallet_connect => try runWalletConnect(allocator, args, writer),
        .wallet_disconnect => try runWalletDisconnect(allocator, args, writer),
        .wallet_passkey_list => try runWalletAccounts(allocator, args, writer, true),
        .wallet_passkey_register => try runWalletPasskeyRegister(allocator, args, writer),
        .wallet_passkey_login => try runWalletPasskeyLogin(allocator, args, writer),
        .wallet_passkey_revoke => try runWalletPasskeyRevoke(allocator, args, writer),
        .wallet_session_create => try runWalletSessionCreate(allocator, args, writer),
        .wallet_session_list => try runWalletSessionList(allocator, args, writer),
        .wallet_session_revoke => try runWalletSessionRevoke(allocator, args, writer),
        .wallet_policy_inspect => try runWalletPolicyInspect(allocator, args, writer),
        .wallet_export_public => {
            var resolved = try resolveWalletEntrySummary(allocator, args);
            defer resolved.deinit(allocator);
            const summary = OwnedWalletPublicExportSummary{
                .source_kind = resolved.source_kind,
                .selector = resolved.selector,
                .alias = resolved.alias,
                .name = resolved.name,
                .address = resolved.address,
                .public_key = resolved.public_key,
                .network = resolved.network,
                .state = resolved.state,
                .active_selector = resolved.active_selector,
                .active_match = resolved.active_match,
            };
            try formatWalletPublicExportSummary(writer, &summary, args.wallet_json, args.pretty);
        },
        .wallet_signer_inspect => {
            var resolved = try resolveWalletEntrySummary(allocator, args);
            defer resolved.deinit(allocator);
            const summary = OwnedWalletSignerInspectSummary{
                .source_kind = resolved.source_kind,
                .selector = resolved.selector,
                .alias = resolved.alias,
                .name = resolved.name,
                .address = resolved.address,
                .public_key = resolved.public_key,
                .network = resolved.network,
                .state = resolved.state,
                .active_selector = resolved.active_selector,
                .active_match = resolved.active_match,
                .can_sign_locally = resolved.can_sign_locally,
                .sender_resolution_kind = if (resolved.address != null) "address" else "missing",
                .registry_path = resolved.registry_path,
                .keystore_path = resolved.keystore_path,
                .wallet_state_path = resolved.wallet_state_path,
            };
            try formatWalletSignerInspectSummary(writer, &summary, args.wallet_json, args.pretty);
        },
        .wallet_address => {
            const resolved = try resolveWalletOwner(allocator, args);
            defer if (resolved.owned) |value| allocator.free(value);
            try writer.print("{s}\n", .{resolved.owner});
        },
        .wallet_balance => {
            const resolved = try resolveWalletOwner(allocator, args);
            defer if (resolved.owned) |value| allocator.free(value);
            try printBalanceSummaryForOwner(allocator, rpc, writer, resolved.owner, args);
        },
        .wallet_coins, .wallet_objects => {
            const resolved = try resolveWalletOwner(allocator, args);
            defer if (resolved.owned) |value| allocator.free(value);

            var result = try rpc.runResourceQueryAction(
                allocator,
                try resourceQueryFromArgs(args, resolved.owner),
                resourceQueryActionFromArgs(args),
            );
            defer result.deinit(allocator);
            try printResourceQueryActionResult(allocator, writer, result, args.pretty);
        },
        .wallet_fund => try runWalletFund(
            allocator,
            rpc,
            args,
            writer,
            programmatic_provider orelse cli_provider,
        ),
        .wallet_intent_build => {
            const intent_json = try buildWalletIntentJsonFromArgs(allocator, args, "send");
            defer allocator.free(intent_json);
            try printResponse(allocator, writer, intent_json, args.pretty);
        },
        .wallet_intent_dry_run => {
            var derived_args = args.*;
            derived_args.command = .request_dry_run;
            return try runCommandWithProgrammaticProvider(
                allocator,
                rpc,
                &derived_args,
                writer,
                effective_programmatic_provider,
            );
        },
        .wallet_intent_send => {
            var derived_args = args.*;
            derived_args.command = .request_send;
            return try runCommandWithProgrammaticProvider(
                allocator,
                rpc,
                &derived_args,
                writer,
                effective_programmatic_provider,
            );
        },
        .request_build => {
            const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
            defer allocator.free(request_json);
            const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-built");
            defer allocator.free(entry_id);
            try upsertRequestLifecycleEntry(
                allocator,
                entry_id,
                "request_artifact",
                "built",
                request_json,
                null,
                null,
                args.request_correlation_id,
                0,
                null,
            );
            try printResponse(allocator, writer, request_json, args.pretty);
        },
        .request_inspect => {
            const summary_json = try buildRequestInspectSummaryJson(allocator, args);
            defer allocator.free(summary_json);
            try printResponse(allocator, writer, summary_json, args.pretty);
        },
        .request_dry_run => {
            const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
            defer allocator.free(request_json);
            var derived_args = args.*;
            derived_args.command = .tx_dry_run;
            var output = std.ArrayList(u8){};
            defer output.deinit(allocator);
            try runCommandWithProgrammaticProvider(
                allocator,
                rpc,
                &derived_args,
                output.writer(allocator),
                effective_programmatic_provider,
            );
            var summary = try summarizeRequestLifecycleOutput(allocator, output.items, .dry_run);
            defer summary.deinit(allocator);
            if (!summary.is_challenge_prompt) {
                const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-resolved");
                defer allocator.free(entry_id);
                try upsertRequestLifecycleEntry(
                    allocator,
                    entry_id,
                    "dry_run_result",
                    summary.next_state.?,
                    request_json,
                    output.items,
                    summary.digest,
                    args.request_correlation_id,
                    0,
                    null,
                );
            }
            try writer.writeAll(output.items);
        },
        .request_sponsor => {
            const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
            defer allocator.free(request_json);
            const envelope_json = try buildRequestSponsorEnvelopeJson(allocator, args);
            defer allocator.free(envelope_json);
            const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-sponsored");
            defer allocator.free(entry_id);
            try upsertRequestLifecycleEntry(
                allocator,
                entry_id,
                "sponsor_envelope",
                "sponsored",
                request_json,
                envelope_json,
                null,
                args.request_correlation_id,
                0,
                null,
            );
            try printResponse(allocator, writer, envelope_json, args.pretty);
        },
        .request_sign => {
            const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
            defer allocator.free(request_json);
            var derived_args = args.*;
            derived_args.command = .tx_payload;
            var output = std.ArrayList(u8){};
            defer output.deinit(allocator);
            runCommandWithProgrammaticProvider(
                allocator,
                rpc,
                &derived_args,
                output.writer(allocator),
                effective_programmatic_provider,
            ) catch |err| {
                const error_message = try ownedRequestLifecycleErrorMessage(allocator, rpc, err);
                defer allocator.free(error_message);
                const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-signed");
                defer allocator.free(entry_id);
                try upsertRequestLifecycleEntry(
                    allocator,
                    entry_id,
                    "execute_payload",
                    "failed",
                    request_json,
                    if (output.items.len != 0) output.items else null,
                    null,
                    args.request_correlation_id,
                    0,
                    error_message,
                );
                return err;
            };
            var summary = try summarizeRequestLifecycleOutput(allocator, output.items, .sign);
            defer summary.deinit(allocator);
            const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-signed");
            defer allocator.free(entry_id);
            try upsertRequestLifecycleEntry(
                allocator,
                entry_id,
                "execute_payload",
                if (summary.is_challenge_prompt) "challenge_required" else summary.next_state.?,
                request_json,
                output.items,
                summary.digest,
                args.request_correlation_id,
                0,
                null,
            );
            try writer.writeAll(output.items);
        },
        .request_send => {
            const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
            defer allocator.free(request_json);
            var derived_args = args.*;
            derived_args.command = .tx_send;
            var output = std.ArrayList(u8){};
            defer output.deinit(allocator);
            runCommandWithProgrammaticProvider(
                allocator,
                rpc,
                &derived_args,
                output.writer(allocator),
                effective_programmatic_provider,
            ) catch |err| {
                const error_message = try ownedRequestLifecycleErrorMessage(allocator, rpc, err);
                defer allocator.free(error_message);
                const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-send");
                defer allocator.free(entry_id);
                try upsertRequestLifecycleEntry(
                    allocator,
                    entry_id,
                    "request_execution",
                    "failed",
                    request_json,
                    if (output.items.len != 0) output.items else null,
                    null,
                    args.request_correlation_id,
                    0,
                    error_message,
                );
                return err;
            };
            var summary = try summarizeRequestLifecycleOutput(allocator, output.items, .send);
            defer summary.deinit(allocator);
            const entry_id = try resolvedRequestLifecycleEntryId(allocator, args, "request-send");
            defer allocator.free(entry_id);
            try upsertRequestLifecycleEntry(
                allocator,
                entry_id,
                "request_execution",
                if (summary.is_challenge_prompt) "challenge_required" else summary.next_state.?,
                request_json,
                output.items,
                summary.digest,
                args.request_correlation_id,
                if (summary.is_challenge_prompt) 0 else 1,
                null,
            );
            try writer.writeAll(output.items);
        },
        .request_schedule => {
            const schedule_id = try resolvedRequestScheduleId(allocator, args);
            defer allocator.free(schedule_id);

            const request_json = try buildRequestArtifactJsonFromArgs(allocator, args);
            defer allocator.free(request_json);

            const schedule_json = try buildRequestScheduleJobJson(allocator, args, schedule_id);
            defer allocator.free(schedule_json);

            try storeScheduledRequestEntry(allocator, args, schedule_id, request_json, schedule_json);
            try printResponse(allocator, writer, schedule_json, args.pretty);
        },
        .request_list => {
            var state = try request_state.loadDefaultRequestState(allocator);
            defer state.deinit(allocator);

            const list_json = try buildRequestStateListJson(allocator, &state);
            defer allocator.free(list_json);
            try printResponse(allocator, writer, list_json, args.pretty);
        },
        .request_cancel => {
            const entry_id = args.request_entry_id orelse return error.InvalidCli;

            var state = try request_state.loadDefaultRequestState(allocator);
            defer state.deinit(allocator);

            const index = findRequestStateEntryIndex(&state, entry_id) orelse return error.InvalidCli;
            if (!std.mem.eql(u8, state.entries[index].kind, "schedule_job")) return error.InvalidCli;

            const now_ms = std.time.milliTimestamp();
            try setRequestStateEntryStateAt(allocator, &state.entries[index], "cancelled", now_ms);

            const response_json = try buildRequestStateEntryActionJson(allocator, "cancelled", &state.entries[index]);
            defer allocator.free(response_json);

            try request_state.writeDefaultRequestState(allocator, &state);
            try printResponse(allocator, writer, response_json, args.pretty);
        },
        .request_resume => {
            const entry_id = args.request_entry_id orelse return error.InvalidCli;

            var state = try request_state.loadDefaultRequestState(allocator);
            defer state.deinit(allocator);

            const index = findRequestStateEntryIndex(&state, entry_id) orelse return error.InvalidCli;
            if (!std.mem.eql(u8, state.entries[index].kind, "schedule_job")) return error.InvalidCli;
            if (!std.mem.eql(u8, state.entries[index].state, "cancelled")) return error.InvalidCli;

            const now_ms = std.time.milliTimestamp();
            try setRequestStateEntryStateAt(allocator, &state.entries[index], "scheduled", now_ms);

            const response_json = try buildRequestStateEntryActionJson(allocator, "resumed", &state.entries[index]);
            defer allocator.free(response_json);

            try request_state.writeDefaultRequestState(allocator, &state);
            try printResponse(allocator, writer, response_json, args.pretty);
        },
        .request_rebroadcast => {
            const entry_id = args.request_entry_id orelse return error.InvalidCli;

            var state = try request_state.loadDefaultRequestState(allocator);
            defer state.deinit(allocator);

            const index = findRequestStateEntryIndex(&state, entry_id) orelse return error.InvalidCli;
            const stored_request_json = state.entries[index].request_json orelse return error.InvalidCli;

            var derived_args = try buildDerivedRequestCommandArgs(allocator, args, .tx_send, stored_request_json);
            defer derived_args.deinit(allocator);

            var execute_output = std.ArrayList(u8){};
            defer execute_output.deinit(allocator);

            runCommandWithProgrammaticProvider(
                allocator,
                rpc,
                &derived_args,
                execute_output.writer(allocator),
                effective_programmatic_provider,
            ) catch |err| {
                const error_message = try ownedRequestLifecycleErrorMessage(allocator, rpc, err);
                defer allocator.free(error_message);

                const now_ms = std.time.milliTimestamp();
                try setRequestStateEntryStateAt(allocator, &state.entries[index], "failed", now_ms);
                if (execute_output.items.len != 0) {
                    try replaceOptionalRequestStateField(
                        allocator,
                        &state.entries[index].artifact_json,
                        execute_output.items,
                    );
                }
                try replaceOptionalRequestStateField(allocator, &state.entries[index].last_error, error_message);
                try request_state.writeDefaultRequestState(allocator, &state);
                return err;
            };

            var summary = try summarizeRequestLifecycleOutput(allocator, execute_output.items, .send);
            defer summary.deinit(allocator);
            const now_ms = std.time.milliTimestamp();
            if (!summary.is_challenge_prompt) {
                state.entries[index].submit_count += 1;
            }
            try setRequestStateEntryStateAt(
                allocator,
                &state.entries[index],
                if (summary.is_challenge_prompt) "challenge_required" else summary.next_state.?,
                now_ms,
            );
            try replaceOptionalRequestStateField(allocator, &state.entries[index].artifact_json, execute_output.items);
            if (summary.digest) |digest| {
                try replaceOptionalRequestStateField(allocator, &state.entries[index].digest, digest);
            }
            try replaceOptionalRequestStateField(allocator, &state.entries[index].last_error, null);
            try request_state.writeDefaultRequestState(allocator, &state);
            try writer.writeAll(execute_output.items);
        },
        .request_status => {
            try runTrackedRequestStatusLikeCommand(
                allocator,
                rpc,
                args,
                writer,
                effective_programmatic_provider,
                .tx_status,
            );
        },
        .request_confirm => {
            try runTrackedRequestStatusLikeCommand(
                allocator,
                rpc,
                args,
                writer,
                effective_programmatic_provider,
                .tx_confirm,
            );
        },
        .account_resources => {
            const resolved = try resolveAccountQueryOwner(allocator, args);
            defer if (resolved.owned) |value| allocator.free(value);

            var result = try rpc.runReadQueryAction(
                allocator,
                .{
                    .resources = try resourceDiscoveryQueryFromArgs(args, resolved.owner),
                },
                readQueryActionFromArgs(args),
            );
            defer result.deinit(allocator);
            try printReadQueryActionResult(allocator, writer, result, args.pretty);
        },
        .account_balance => {
            const resolved = try resolveAccountQueryOwner(allocator, args);
            defer if (resolved.owned) |value| allocator.free(value);
            try printBalanceSummaryForOwner(allocator, rpc, writer, resolved.owner, args);
        },
        .account_coins, .account_objects => {
            const resolved = try resolveAccountQueryOwner(allocator, args);
            defer if (resolved.owned) |value| allocator.free(value);

            var result = try rpc.runResourceQueryAction(
                allocator,
                try resourceQueryFromArgs(args, resolved.owner),
                resourceQueryActionFromArgs(args),
            );
            defer result.deinit(allocator);
            try printResourceQueryActionResult(allocator, writer, result, args.pretty);
        },
        .account_list, .account_info, .events, .move_package, .move_module, .move_function, .object_get, .object_dynamic_fields, .object_dynamic_field_object, .tx_status, .tx_confirm => {
            switch (args.command) {
                .tx_status, .tx_confirm => {
                    const digest = args.tx_digest orelse return error.InvalidCli;
                    if (std.mem.eql(u8, digest, "")) return error.InvalidCli;
                },
                else => {},
            }

            var move_function_query_args = args.*;
            const move_function_args = blk: {
                if (args.command != .move_function) break :blk args;
                if (args.tx_build_sender != null or args.signers.items.len != 0 or args.from_keystore) break :blk args;
                if (effective_programmatic_provider) |provider| {
                    if (defaultSenderFromProgrammaticProvider(provider)) |sender| {
                        move_function_query_args.tx_build_sender = sender;
                        break :blk &move_function_query_args;
                    }
                }
                if (try resolvedMoveFunctionQuerySenderFromArgs(rpc, allocator, args)) |sender| {
                    move_function_query_args.owned_tx_build_sender = sender;
                    move_function_query_args.tx_build_sender = sender;
                    break :blk &move_function_query_args;
                }
                break :blk args;
            };
            defer if (move_function_args == &move_function_query_args) {
                if (move_function_query_args.owned_tx_build_sender) |value| allocator.free(value);
            };

            if (args.command == .move_function and
                (args.move_function_template_output != null or
                    args.move_function_execute_dry_run or
                    args.move_function_execute_send))
            {
                var query = try readQueryFromArgs(allocator, move_function_args);
                defer query.deinit(allocator);
                var result = try rpc.runReadQueryAction(
                    allocator,
                    query,
                    .summarize,
                );
                defer result.deinit(allocator);

                if (args.move_function_execute_dry_run or args.move_function_execute_send) {
                    const exec_command: cli.Command = if (args.move_function_execute_dry_run) .tx_dry_run else .tx_send;
                    const request_selection = moveFunctionExecutionRequestArtifact(
                        allocator,
                        result,
                        exec_command,
                    ) catch |err| switch (err) {
                        error.UnresolvedMoveFunctionExecutionTemplate => {
                            try recordUnresolvedMoveFunctionExecutionError(allocator, rpc, result);
                            return err;
                        },
                        else => return err,
                    };
                    var derived_args = try buildDerivedMoveFunctionExecutionArgs(
                        allocator,
                        args,
                        exec_command,
                        request_selection.request_json,
                    );
                    defer derived_args.deinit(allocator);
                    try runCommandWithProgrammaticProvider(
                        allocator,
                        rpc,
                        &derived_args,
                        writer,
                        effective_programmatic_provider,
                    );
                    return;
                }

                if (args.move_function_template_output) |output_kind| {
                    try printMoveFunctionTemplateOutput(writer, result, output_kind);
                    return;
                }
            }

            var query = try readQueryFromArgs(allocator, move_function_args);
            defer query.deinit(allocator);
            var result = try rpc.runReadQueryAction(
                allocator,
                query,
                readQueryActionFromArgs(args),
            );
            defer result.deinit(allocator);
            if (args.command == .move_function) {
                if (args.move_function_template_output) |output_kind| {
                    try printMoveFunctionTemplateOutput(writer, result, output_kind);
                    return;
                }
            }
            try printReadQueryActionResult(allocator, writer, result, args.pretty);
        },
        .rpc => {
            const method = args.method orelse return error.InvalidCli;
            const params = args.params orelse "[]";
            const response = try rpc.call(method, params);
            defer rpc.allocator.free(response);
            try printResponse(allocator, writer, response, args.pretty);
        },
        .tx_build => {
            const kind = args.tx_build_kind orelse return error.InvalidCli;
            try validateTxBuildArguments(args);
            if (args.tx_session_response != null and !args.tx_build_emit_tx_block) {
                return error.InvalidCli;
            }

            switch (kind) {
                .move_call => {
                    if (args.tx_build_emit_tx_block) {
                        if (try buildLocalCommandSourceTransactionBlock(allocator, rpc, args, effective_programmatic_provider)) |tx_block| {
                            defer allocator.free(tx_block);
                            if (args.tx_send_summarize) {
                                var summary = try rpc.summarizeBuildArtifact(allocator, tx_block);
                                defer summary.deinit(allocator);
                                try printStructuredJson(writer, summary, args.pretty);
                            } else {
                                try writer.print("{s}", .{tx_block});
                            }
                            return;
                        }
                    }
                    if (try hasSelectedMoveCallArgumentRequests(allocator, args)) {
                        if (args.tx_build_emit_tx_block) {
                            var result = try runProgrammaticActionMaybeAutoGasPaymentOrChallengePrompt(
                                allocator,
                                rpc,
                                args,
                                &.{},
                                effective_programmatic_provider,
                                if (args.tx_send_summarize)
                                    .{ .build_artifact_summarize = .transaction_block }
                                else
                                    .{ .build_artifact = .transaction_block },
                            );
                            defer result.deinit(allocator);
                            try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                        } else {
                            const instruction = try buildSelectedMoveCallInstructionFromArgs(allocator, rpc, args);
                            defer allocator.free(instruction);
                            if (args.tx_send_summarize) {
                                var summary = try rpc.summarizeBuildArtifact(allocator, instruction);
                                defer summary.deinit(allocator);
                                try printStructuredJson(writer, summary, args.pretty);
                            } else {
                                try writer.print("{s}\n", .{instruction});
                            }
                        }
                    } else if (args.tx_build_emit_tx_block and (args.tx_build_auto_gas_payment or gasPaymentContainsSelectedRequestToken(args))) {
                        var result = try runProgrammaticActionMaybeAutoGasPaymentOrChallengePrompt(
                            allocator,
                            rpc,
                            args,
                            &.{},
                            effective_programmatic_provider,
                            if (args.tx_send_summarize)
                                .{ .build_artifact_summarize = .transaction_block }
                            else
                                .{ .build_artifact = .transaction_block },
                        );
                        defer result.deinit(allocator);
                        try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                    } else if (args.tx_build_emit_tx_block) {
                        const tx_block = try buildTxBuildTransactionBlockFromArgs(allocator, args);
                        defer allocator.free(tx_block);
                        if (args.tx_send_summarize) {
                            var summary = try rpc.summarizeBuildArtifact(allocator, tx_block);
                            defer summary.deinit(allocator);
                            try printStructuredJson(writer, summary, args.pretty);
                        } else {
                            try writer.print("{s}", .{tx_block});
                        }
                    } else {
                        const instruction = try buildTxBuildInstructionFromArgs(allocator, args);
                        defer allocator.free(instruction);
                        if (args.tx_send_summarize) {
                            var summary = try rpc.summarizeBuildArtifact(allocator, instruction);
                            defer summary.deinit(allocator);
                            try printStructuredJson(writer, summary, args.pretty);
                        } else {
                            try writer.print("{s}\n", .{instruction});
                        }
                    }
                },
                .programmable => {
                    if (try buildLocalCommandSourceTransactionBlock(allocator, rpc, args, effective_programmatic_provider)) |tx_block| {
                        defer allocator.free(tx_block);
                        if (args.tx_send_summarize) {
                            var summary = try rpc.summarizeBuildArtifact(allocator, tx_block);
                            defer summary.deinit(allocator);
                            try printStructuredJson(writer, summary, args.pretty);
                        } else {
                            try writer.print("{s}", .{tx_block});
                        }
                        return;
                    }
                    if (programmaticCommandsContainSelectedRequestTokens(args) or args.tx_build_auto_gas_payment or gasPaymentContainsSelectedRequestToken(args)) {
                        var result = try runProgrammaticActionMaybeAutoGasPaymentOrChallengePrompt(
                            allocator,
                            rpc,
                            args,
                            &.{},
                            effective_programmatic_provider,
                            if (args.tx_send_summarize)
                                .{ .build_artifact_summarize = .transaction_block }
                            else
                                .{ .build_artifact = .transaction_block },
                        );
                        defer result.deinit(allocator);
                        try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                    } else {
                        const tx_block = try buildTxBuildTransactionBlockFromArgs(allocator, args);
                        defer allocator.free(tx_block);
                        if (args.tx_send_summarize) {
                            var summary = try rpc.summarizeBuildArtifact(allocator, tx_block);
                            defer summary.deinit(allocator);
                            try printStructuredJson(writer, summary, args.pretty);
                        } else {
                            try writer.print("{s}", .{tx_block});
                        }
                    }
                },
            }
        },
        .tx_simulate => {
            if (cli.supportsProgrammableInput(args)) {
                if (try buildLocalCommandSourceInspectPayload(allocator, rpc, args, effective_programmatic_provider)) |params| {
                    defer allocator.free(params);
                    const response = try rpc.sendTxInspect(params);
                    defer rpc.allocator.free(response);
                    if (args.tx_send_summarize) {
                        var insights = try rpc.summarizeInspectResponse(allocator, response);
                        defer insights.deinit(allocator);
                        try printStructuredJson(writer, insights, args.pretty);
                    } else {
                        try printResponse(allocator, writer, response, args.pretty);
                    }
                    return;
                }
                var result = try runProgrammaticActionMaybeAutoGasPaymentOrChallengePrompt(
                    allocator,
                    rpc,
                    args,
                    &.{},
                    effective_programmatic_provider,
                    if (args.tx_send_summarize) .inspect_summarize else .inspect,
                );
                defer result.deinit(allocator);
                try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                return;
            }
            const params = try buildInspectPayloadFromArgs(allocator, args);
            defer allocator.free(params);
            const response = try rpc.sendTxInspect(params);
            defer rpc.allocator.free(response);
            if (args.tx_send_summarize) {
                var insights = try rpc.summarizeInspectResponse(allocator, response);
                defer insights.deinit(allocator);
                try printStructuredJson(writer, insights, args.pretty);
            } else {
                try printResponse(allocator, writer, response, args.pretty);
            }
        },
        .tx_dry_run => {
            if (cli.supportsProgrammableInput(args)) {
                if (args.tx_bytes != null) return error.InvalidCli;
                if (try buildLocalCommandSourceTxBytes(allocator, rpc, args, effective_programmatic_provider)) |tx_bytes| {
                    defer allocator.free(tx_bytes);
                    try sendDryRunAndMaybeSummarize(allocator, rpc, args, tx_bytes, writer);
                    return;
                }

                const tx_bytes = try buildUnsafeCommandSourceTxBytes(allocator, rpc, args);
                defer allocator.free(tx_bytes);
                try sendDryRunAndMaybeSummarize(allocator, rpc, args, tx_bytes, writer);
                return;
            }

            const tx_bytes = args.tx_bytes orelse return error.InvalidCli;
            try sendDryRunAndMaybeSummarize(allocator, rpc, args, tx_bytes, writer);
        },
        .tx_payload => {
            const signatures = if (args.signatures.items.len > 0) args.signatures.items else &.{};
            if (cli.supportsProgrammableInput(args)) {
                if (args.tx_bytes != null) return error.InvalidCli;
                const local_payload_action = if (args.tx_send_summarize)
                    client.rpc_client.ProgrammaticClientAction{ .build_artifact_summarize = .execute_payload }
                else
                    client.rpc_client.ProgrammaticClientAction{ .build_artifact = .execute_payload };
                if (effective_programmatic_provider) |provider| {
                    if (try runLocalCommandSourceAction(
                        allocator,
                        rpc,
                        args,
                        provider,
                        allowReferenceGasPriceFallbackForLocalProviderPath(provider),
                        local_payload_action,
                    )) |local_result| {
                        var result = local_result;
                        defer result.deinit(allocator);
                        try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                        return;
                    }
                } else if (try buildLocalCommandSourceExecutePayload(allocator, rpc, args, null)) |payload| {
                    defer allocator.free(payload);
                    if (args.tx_send_summarize) {
                        var summarized = try rpc.summarizeArtifact(allocator, .execute_payload, payload);
                        defer summarized.deinit(allocator);
                        switch (summarized) {
                            .execute_payload => |summary| try printStructuredJson(writer, summary, args.pretty),
                            else => return error.InvalidResponse,
                        }
                    } else {
                        try printResponse(allocator, writer, payload, args.pretty);
                    }
                    return;
                }
                var result = try runProgrammaticActionMaybeAutoGasPaymentOrChallengePrompt(
                    allocator,
                    rpc,
                    args,
                    signatures,
                    effective_programmatic_provider,
                    local_payload_action,
                );
                defer result.deinit(allocator);
                try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
            } else {
                const payload =
                    try buildExecutePayloadFromArgs(allocator, args, signatures, null);
                defer allocator.free(payload);
                if (args.tx_send_summarize) {
                    var summarized = try rpc.summarizeArtifact(allocator, .execute_payload, payload);
                    defer summarized.deinit(allocator);
                    switch (summarized) {
                        .execute_payload => |summary| try printStructuredJson(writer, summary, args.pretty),
                        else => return error.InvalidResponse,
                    }
                } else {
                    try printResponse(allocator, writer, payload, args.pretty);
                }
            }
        },
        .natural_do => {
            // If --intent-json is provided, use it directly (Claude Code pre-parsed)
            // Otherwise, parse the natural language query locally
            var intent_result: intent_parser.IntentResult = blk: {
                if (args.intent_json) |json| {
                    // Parse pre-structured intent from Claude Code
                    break :blk try intent_parser.parseIntentJson(allocator, json);
                } else if (args.natural_query) |query| {
                    // Local parsing without API call
                    break :blk try intent_parser.parseNaturalLanguageIntent(allocator, query, null);
                } else {
                    return error.InvalidCli;
                }
            };
            defer intent_result.deinit(allocator);

            switch (intent_result) {
                .swap => |swap_intent| {
                    try writer.print("Parsed intent: swap {s} {s} -> {s} (slippage: {d} bps)\n", .{
                        swap_intent.amount orelse "all",
                        swap_intent.from_token,
                        swap_intent.to_token,
                        swap_intent.slippage_bps,
                    });

                    // TODO: Implement actual swap execution
                    // 1. Resolve token types from symbols
                    // 2. Find best Cetus pool
                    // 3. Calculate amounts
                    // 4. Build and execute transaction
                    try writer.print("\n(This is a preview. Full swap execution coming soon.)\n", .{});
                },
                .unsupported => |unsupported| {
                    try writer.print("Unsupported intent: {s}\n", .{unsupported});
                    try writer.print("Currently only 'swap' intents are supported.\n", .{});
                },
            }
        },
        .tx_send => {
            const provider_available = effective_programmatic_provider != null;
            const can_execute_without_direct_signatures = cli.supportsProgrammableInput(args) and
                (provider_available or hasKeystoreBackedSignerSource(args));
            if (args.signatures.items.len == 0 and !can_execute_without_direct_signatures) {
                return error.InvalidCli;
            }
            if (cli.supportsProgrammableInput(args)) {
                if (args.tx_bytes != null) return error.InvalidCli;
                const action = if (args.tx_send_observe)
                    client.rpc_client.ProgrammaticClientAction{ .execute_confirm_observe = .{
                        .timeout_ms = args.confirm_timeout_ms orelse std.math.maxInt(u64),
                        .poll_ms = args.confirm_poll_ms,
                    } }
                else if (args.tx_send_summarize)
                    if (args.tx_send_wait)
                        client.rpc_client.ProgrammaticClientAction{ .execute_confirm_summarize = .{
                            .timeout_ms = args.confirm_timeout_ms orelse std.math.maxInt(u64),
                            .poll_ms = args.confirm_poll_ms,
                        } }
                    else
                        .execute_summarize
                else if (args.tx_send_wait)
                    client.rpc_client.ProgrammaticClientAction{ .execute_confirm = .{
                        .timeout_ms = args.confirm_timeout_ms orelse std.math.maxInt(u64),
                        .poll_ms = args.confirm_poll_ms,
                    } }
                else
                    .execute;
                if (effective_programmatic_provider) |provider| {
                    if (try runLocalCommandSourceAction(allocator, rpc, args, provider, true, action)) |local_result| {
                        var result = local_result;
                        defer result.deinit(allocator);
                        try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                        return;
                    }
                } else if (try buildLocalCommandSourceExecutePayload(allocator, rpc, args, null)) |payload| {
                    defer allocator.free(payload);
                    try sendExecuteAndMaybeWaitForConfirmation(allocator, rpc, args, payload, writer);
                    return;
                }
                var result = try runProgrammaticActionMaybeAutoGasPaymentOrChallengePrompt(
                    allocator,
                    rpc,
                    args,
                    args.signatures.items,
                    effective_programmatic_provider,
                    action,
                );
                defer result.deinit(allocator);
                try printProgrammaticActionOrChallengePromptResult(allocator, writer, result, args.pretty);
                return;
            }
            const payload = try buildExecutePayloadFromArgs(
                allocator,
                args,
                args.signatures.items,
                null,
            );
            defer allocator.free(payload);
            try sendExecuteAndMaybeWaitForConfirmation(allocator, rpc, args, payload, writer);
        },
    }
}

pub fn runCommand(
    allocator: std.mem.Allocator,
    rpc: *client.SuiRpcClient,
    args: *const cli.ParsedArgs,
    writer: anytype,
) !void {
    return try runCommandWithProgrammaticProvider(allocator, rpc, args, writer, null);
}

test "runCommand tx_payload writes expected payload" {
    const testing = std.testing;

    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    var args = cli.ParsedArgs{
        .command = .tx_payload,
        .has_command = true,
        .tx_bytes = "AAABBB",
        .tx_options = "{\"skipChecks\":true}",
    };
    try args.signatures.append(allocator, "sig-a");
    try args.signatures.append(allocator, "sig-b");
    defer args.signatures.deinit(allocator);

    var rpc = try client.SuiRpcClient.init(allocator, "http://example.local");
    defer rpc.deinit();

    var output = std.ArrayList(u8){};
    defer output.deinit(allocator);
    const writer = output.writer(allocator);

    try runCommand(allocator, &rpc, &args, writer);
    try testing.expectEqualStrings("[\"AAABBB\",[\"sig-a\",\"sig-b\"],{\"skipChecks\":true}]\n", output.items);
}

test "runCommand tx_payload with raw tx bytes and --summarize prints payload summaries" {
    const testing = std.testing;

    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    var args = cli.ParsedArgs{
        .command = .tx_payload,
        .has_command = true,
        .tx_bytes = "AAABBB",
        .tx_options = "{\"skipChecks\":true}",
        .tx_send_summarize = true,
    };
    try args.signatures.append(allocator, "sig-a");
    try args.signatures.append(allocator, "sig-b");
    defer args.signatures.deinit(allocator);

    var rpc = try client.SuiRpcClient.init(allocator, "http://example.local");
    defer rpc.deinit();

    var output = std.ArrayList(u8){};
    defer output.deinit(allocator);

    try runCommand(allocator, &rpc, &args, output.writer(allocator));

    const summary = try std.json.parseFromSlice(std.json.Value, allocator, output.items, .{});
    defer summary.deinit();
    try testing.expectEqualStrings("tx_bytes", summary.value.object.get("data_kind").?.string);
    try testing.expectEqual(@as(i64, 2), summary.value.object.get("signature_count").?.integer);
    try testing.expect(summary.value.object.get("has_options").?.bool);
}

test "runCommand tx_payload rejects non-object options for raw tx bytes" {
    const testing = std.testing;

    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

