    try testing.expectEqualStrings("MakeMoveVec", preferred_commands.value.array.items[1].object.get("kind").?.string);
    const make_move_vec_elements = preferred_commands.value.array.items[1].object.get("elements").?.array.items;
    try testing.expectEqual(@as(usize, 1), make_move_vec_elements.len);
    try testing.expectEqual(@as(i64, 0), make_move_vec_elements[0].object.get("NestedResult").?.array.items[0].integer);
    try testing.expectEqual(@as(i64, 0), make_move_vec_elements[0].object.get("NestedResult").?.array.items[1].integer);

    try testing.expectEqualStrings("MoveCall", preferred_commands.value.array.items[2].object.get("kind").?.string);
    const move_call_args = preferred_commands.value.array.items[2].object.get("arguments").?.array.items;
    try testing.expectEqual(@as(i64, 1), move_call_args[0].object.get("Result").?.integer);
    try testing.expectEqualStrings(
        "select:{\"kind\":\"object_input\",\"objectId\":\"0xcoin-big\",\"inputKind\":\"imm_or_owned\",\"version\":9,\"digest\":\"coin-digest-big\"}",
        move_call_args[1].string,
    );
    try testing.expectEqual(@as(i64, 50), move_call_args[2].integer);
}

