                "{\"result\":{\"data\":{\"objectId\":\"0xobject\",\"version\":\"7\",\"digest\":\"digest-1\",\"type\":\"0x2::counter::Counter\",\"owner\":{\"AddressOwner\":\"0xowner\"},\"previousTransaction\":\"0xprev\",\"storageRebate\":\"42\"}}}",
