            }
            if (std.mem.eql(u8, req.method, "unsafe_moveCall") or std.mem.eql(u8, req.method, "unsafe_batchTransaction")) {
                ctx.unsafe_calls += 1;
                return alloc.dupe(u8, "{\"result\":{\"txBytes\":\"AQIDBA==\"}}");
