                            const seen = @as(*bool, @ptrCast(@alignCast(context)));
                            seen.* = true;
                            return .{};
                        }
                    }.call,
                },
                .session_challenge = .{
                    .passkey = .{
                        .rp_id = "wallet.example",
                        .challenge_b64url = "challenge-local-builder-payload",
                    },
