    try testing.expectEqual(@as(usize, 0), state.unsafe);
    try testing.expect(std.mem.indexOf(u8, output.items, "\"account_address\":\"0x123\"") != null);
    try testing.expect(std.mem.indexOf(u8, output.items, "\"challenge\"") != null);
}

